def _get_codex_auto_agent_header(headers: dict[str, Any], header_name: str) -> Optional[str]:
    for key, value in headers.items():
        if not isinstance(key, str) or key.lower() != header_name.lower():
            continue
        cleaned = _clean_codex_auth_value(value)
        if cleaned is not None:
            return cleaned
    return None


def _hash_codex_auto_agent_lane_value(value: str) -> str:
    return hashlib.sha256(value.encode("utf-8")).hexdigest()[:12]


def _resolve_codex_auto_agent_openai_lane_key(
    request: Request,
    *,
    include_session_fallback: bool = True,
) -> str:
    headers = _safe_get_request_headers(request)
    account_id = _get_codex_auto_agent_header(headers, "chatgpt-account-id")
    if account_id is not None:
        return f"chatgpt-account:{account_id}"
    authorization = _get_codex_auto_agent_header(headers, "authorization")
    if authorization is not None:
        return f"auth:{_hash_codex_auto_agent_lane_value(authorization)}"
    if include_session_fallback:
        session_header = _get_codex_auto_agent_header(headers, "session_id") or _get_codex_auto_agent_header(
            headers, "session-id"
        )
        if session_header is not None:
            return f"session:{session_header}"
    return "__default__"


def _resolve_codex_auto_agent_openai_cooldown_lane_key(request: Request) -> str:
    return _resolve_codex_auto_agent_openai_lane_key(
        request,
        include_session_fallback=False,
    )


def _get_codex_auto_agent_lane_state_cache_ttl_seconds() -> float:
    raw_value = _clean_codex_auth_value(os.getenv("AAWM_CODEX_AUTO_AGENT_LANE_STATE_CACHE_TTL_SECONDS"))
    if raw_value is None:
        return _CODEX_AUTO_AGENT_LANE_STATE_CACHE_TTL_SECONDS
    try:
        parsed = float(raw_value)
    except Exception:
        return _CODEX_AUTO_AGENT_LANE_STATE_CACHE_TTL_SECONDS
    return max(0.0, parsed)


def _get_codex_auto_agent_google_lane_cache_key() -> str:
    auth_path = _get_anthropic_adapter_google_auth_file_path()
    if auth_path is not None:
        return f"google-auth:{auth_path.expanduser()}"
    return "google-auth:__default__"


def _get_codex_auto_agent_antigravity_lane_cache_key() -> str:
    auth_path = _get_antigravity_auth_file_path()
    if auth_path is not None:
        return f"antigravity-auth:{auth_path.expanduser()}"
    return "antigravity-auth:__default__"


def _invalidate_codex_auto_agent_google_lane_cache() -> None:
    cache_key = _get_codex_auto_agent_google_lane_cache_key()
    _codex_auto_agent_google_lane_key_until_monotonic_by_key.pop(cache_key, None)
    _codex_auto_agent_google_lane_key_by_key.pop(cache_key, None)


def _invalidate_codex_auto_agent_antigravity_lane_cache() -> None:
    cache_key = _get_codex_auto_agent_antigravity_lane_cache_key()
    _codex_auto_agent_antigravity_lane_key_until_monotonic_by_key.pop(
        cache_key,
        None,
    )
    _codex_auto_agent_antigravity_lane_key_by_key.pop(cache_key, None)


def _invalidate_codex_auto_agent_lane_state_caches() -> None:
    _invalidate_codex_auto_agent_google_lane_cache()
    _invalidate_codex_auto_agent_antigravity_lane_cache()


async def _resolve_codex_auto_agent_google_lane_key() -> str:
    if time.monotonic() < _alias_routing_state.google_lane_negative_until_monotonic:
        return _CODEX_AUTO_AGENT_GOOGLE_AUTH_DEGRADED_LANE_KEY
    cache_key = _get_codex_auto_agent_google_lane_cache_key()
    ttl_seconds = _get_codex_auto_agent_lane_state_cache_ttl_seconds()
    if ttl_seconds > 0:
        async with _codex_auto_agent_lane_state_cache_lock:
            cached_until = _codex_auto_agent_google_lane_key_until_monotonic_by_key.get(cache_key, 0.0)
            if cached_until > time.monotonic():
                cached_lane_key = _codex_auto_agent_google_lane_key_by_key.get(cache_key)
                if isinstance(cached_lane_key, str) and cached_lane_key:
                    return cached_lane_key

    try:
        google_access_token = await _load_valid_local_google_oauth_access_token()
        google_project = await _get_or_load_google_code_assist_project(google_access_token)
        lane_key = _get_google_adapter_rate_limit_key(
            None,
            access_token=google_access_token,
            companion_project=google_project,
        )
    except Exception:
        _invalidate_codex_auto_agent_google_lane_cache()
        _alias_routing_state.google_lane_negative_until_monotonic = (
            time.monotonic() + _CODEX_AUTO_AGENT_GOOGLE_LANE_NEGATIVE_TTL_SECONDS
        )
        if _should_log_aawm_alias_routing_event("google-lane-resolve-failed"):
            verbose_proxy_logger.warning(
                "Codex auto-agent alias could not resolve Google Code Assist lane; "
                "marking auth-degraded (negative-cached %.1fs)",
                _CODEX_AUTO_AGENT_GOOGLE_LANE_NEGATIVE_TTL_SECONDS,
                exc_info=True,
            )
        return _CODEX_AUTO_AGENT_GOOGLE_AUTH_DEGRADED_LANE_KEY

    if ttl_seconds > 0:
        async with _codex_auto_agent_lane_state_cache_lock:
            _codex_auto_agent_google_lane_key_by_key[cache_key] = lane_key
            _codex_auto_agent_google_lane_key_until_monotonic_by_key[cache_key] = time.monotonic() + ttl_seconds
    return lane_key


async def _resolve_codex_auto_agent_google_lane_state() -> Payload:
    lane_key = await _resolve_codex_auto_agent_google_lane_key()
    if lane_key != _CODEX_AUTO_AGENT_GOOGLE_AUTH_DEGRADED_LANE_KEY:
        return {"lane_key": lane_key}
    return {
        "lane_key": lane_key,
        "forced_cooldown_seconds": _CODEX_AUTO_AGENT_AUTH_DEGRADED_COOLDOWN_SECONDS,
        "skip_reason": "auth_degraded",
        "cooldown_state_source": "auth_degraded",
        "failure_phase": "auth",
        "attempted_provider_call": False,
    }


def _is_codex_auto_agent_antigravity_auth_degraded_exception(exc: Any) -> bool:
    return _anthropic_antigravity_provider._is_codex_auto_agent_antigravity_auth_degraded_exception(
        exc,
        runtime=_get_anthropic_antigravity_runtime(),
    )


def _log_codex_auto_agent_antigravity_auth_degraded(exc: HTTPException) -> None:
    now = time.monotonic()
    if now < _alias_routing_state.antigravity_auth_degraded_log_until_monotonic:
        return
    _alias_routing_state.antigravity_auth_degraded_log_until_monotonic = (
        now + _CODEX_AUTO_AGENT_AUTH_DEGRADED_LOG_INTERVAL_SECONDS
    )
    verbose_proxy_logger.warning(
        "Codex auto-agent alias marked Antigravity Code Assist lane degraded; "
        "using auth-degraded lane sentinel until sidecar refresh is available "
        "(provider=antigravity, failure_kind=auth_degraded, status_code=%s, "
        "cooldown_seconds=%.1f, detail=%s)",
        exc.status_code,
        _CODEX_AUTO_AGENT_AUTH_DEGRADED_COOLDOWN_SECONDS,
        str(exc.detail),
    )


async def _resolve_codex_auto_agent_antigravity_lane_key() -> str:
    cache_key = _get_codex_auto_agent_antigravity_lane_cache_key()
    ttl_seconds = _get_codex_auto_agent_lane_state_cache_ttl_seconds()
    if ttl_seconds > 0:
        async with _codex_auto_agent_lane_state_cache_lock:
            cached_until = _codex_auto_agent_antigravity_lane_key_until_monotonic_by_key.get(cache_key, 0.0)
            if cached_until > time.monotonic():
                cached_lane_key = _codex_auto_agent_antigravity_lane_key_by_key.get(cache_key)
                if isinstance(cached_lane_key, str) and cached_lane_key:
                    return cached_lane_key

    try:
        antigravity_access_token = await _load_valid_local_antigravity_access_token()
        antigravity_project = await _get_or_load_google_code_assist_project(
            antigravity_access_token,
            adapter_provider=_ANTIGRAVITY_CODE_ASSIST_ADAPTER_PROVIDER,
        )
        lane_key = "antigravity:{}".format(
            _get_google_adapter_rate_limit_key(
                None,
                access_token=antigravity_access_token,
                companion_project=antigravity_project,
            )
        )
    except Exception as exc:
        if _is_codex_auto_agent_antigravity_auth_degraded_exception(exc):
            _invalidate_codex_auto_agent_antigravity_lane_cache()
            _log_codex_auto_agent_antigravity_auth_degraded(cast(HTTPException, exc))
            return _CODEX_AUTO_AGENT_ANTIGRAVITY_AUTH_DEGRADED_LANE_KEY
        _invalidate_codex_auto_agent_antigravity_lane_cache()
        verbose_proxy_logger.error(
            "Codex auto-agent alias could not resolve Antigravity Code Assist lane; using default lane",
            exc_info=True,
        )
        return "__default__"

    if ttl_seconds > 0 and lane_key != "__default__":
        async with _codex_auto_agent_lane_state_cache_lock:
            _codex_auto_agent_antigravity_lane_key_by_key[cache_key] = lane_key
            _codex_auto_agent_antigravity_lane_key_until_monotonic_by_key[cache_key] = time.monotonic() + ttl_seconds
    return lane_key


async def _resolve_codex_auto_agent_antigravity_lane_state() -> dict[str, Any]:
    lane_key = await _resolve_codex_auto_agent_antigravity_lane_key()
    if lane_key != _CODEX_AUTO_AGENT_ANTIGRAVITY_AUTH_DEGRADED_LANE_KEY:
        return {"lane_key": lane_key}
    return {
        "lane_key": lane_key,
        "forced_cooldown_seconds": _CODEX_AUTO_AGENT_AUTH_DEGRADED_COOLDOWN_SECONDS,
        "skip_reason": "auth_degraded",
        "cooldown_state_source": "auth_degraded",
        "failure_phase": "auth",
        "attempted_provider_call": False,
    }


def _resolve_codex_auto_agent_session_key(
    request: Request,
    request_body: dict[str, Any],
    *,
    alias_model: str = _CODEX_AUTO_AGENT_MODEL_ALIAS,
) -> Optional[str]:
    metadata = request_body.get("litellm_metadata")
    metadata_session_id = metadata.get("session_id") if isinstance(metadata, dict) else None
    session_id = _clean_codex_auth_value(metadata_session_id)
    headers = _safe_get_request_headers(request)
    if session_id is None:
        session_id = _get_codex_auto_agent_header(headers, "session_id") or _get_codex_auto_agent_header(
            headers, "session-id"
        )
    if session_id is None:
        return None
    if alias_model == _CODEX_AUTO_AGENT_MODEL_ALIAS:
        return f"{session_id}:{_resolve_codex_auto_agent_openai_lane_key(request)}"
    return f"{alias_model}:{session_id}:" f"{_resolve_codex_auto_agent_openai_lane_key(request)}"


def _codex_auto_agent_candidate_key(
    candidate: dict[str, Any],
    lane_key: str,
) -> str:
    return "{}:{}:{}".format(
        candidate["provider"],
        candidate["model"],
        lane_key or "__default__",
    )


def _codex_auto_agent_candidate_public_shape(
    candidate: dict[str, Any],
    *,
    lane_key: Optional[str] = None,
    cooldown_seconds: Optional[float] = None,
    reason: Optional[str] = None,
) -> dict[str, Any]:
    shaped = {
        "provider": candidate["provider"],
        "model": candidate["model"],
        "route_family": candidate["route_family"],
        "last_resort": bool(candidate.get("last_resort")),
    }
    if lane_key is not None:
        shaped["lane_key"] = lane_key
    if cooldown_seconds is not None:
        shaped["cooldown_seconds"] = round(float(cooldown_seconds), 3)
    if reason is not None:
        shaped["reason"] = reason
    return shaped


def _reset_openrouter_free_daily_quota_cache() -> None:
    global _openrouter_free_daily_quota_cache
    _openrouter_free_daily_quota_cache = (None, 0.0)


def _parse_openrouter_free_daily_quota_reset_timestamp(
    expected_reset_at: Any,
) -> Optional[float]:
    if isinstance(expected_reset_at, (int, float)):
        return float(expected_reset_at)
    if isinstance(expected_reset_at, datetime):
        reset_dt = expected_reset_at
        if reset_dt.tzinfo is None:
            reset_dt = reset_dt.replace(tzinfo=timezone.utc)
        return reset_dt.timestamp()
    if isinstance(expected_reset_at, str):
        raw_reset = expected_reset_at.strip()
        if not raw_reset:
            return None
        if raw_reset.endswith("Z"):
            raw_reset = raw_reset[:-1] + "+00:00"
        try:
            reset_dt = datetime.fromisoformat(raw_reset)
        except (TypeError, ValueError):
            return None
        if reset_dt.tzinfo is None:
            reset_dt = reset_dt.replace(tzinfo=timezone.utc)
        return reset_dt.timestamp()
    return None


async def _fetch_openrouter_free_daily_quota_row() -> Optional[Any]:
    pool = await _get_aawm_dynamic_injection_pool()
    return await pool.fetchrow(
        """
        SELECT expected_reset_at, remaining_pct
        FROM public.rate_limit_observations
        WHERE provider = $1
          AND quota_key = $2
        ORDER BY observed_at DESC
        LIMIT 1
        """,
        _CODEX_AUTO_AGENT_OPENROUTER_PROVIDER,
        _OPENROUTER_DURABLE_QUOTA_DAILY_KEY,
    )


async def _get_openrouter_free_daily_quota_exhausted_cooldown_seconds() -> float:
    global _openrouter_free_daily_quota_cache

    now_monotonic = time.monotonic()
    cached_reset_at, cached_until = _openrouter_free_daily_quota_cache
    if cached_until > now_monotonic:
        if cached_reset_at is None:
            return 0.0
        return max(0.0, cached_reset_at - time.time())

    async with _openrouter_free_daily_quota_lock:
        cached_reset_at, cached_until = _openrouter_free_daily_quota_cache
        if cached_until > time.monotonic():
            if cached_reset_at is None:
                return 0.0
            return max(0.0, cached_reset_at - time.time())

        reset_at_ts: Optional[float] = None
        try:
            row = await asyncio.wait_for(
                _fetch_openrouter_free_daily_quota_row(),
                timeout=_OPENROUTER_DURABLE_QUOTA_LOOKUP_TIMEOUT_SECONDS,
            )
            if row is not None:
                remaining_pct = row["remaining_pct"]
                try:
                    remaining_pct_float = float(remaining_pct) if remaining_pct is not None else None
                except (TypeError, ValueError):
                    remaining_pct_float = None
                if remaining_pct_float is not None and remaining_pct_float <= 0:
                    reset_at_ts = _parse_openrouter_free_daily_quota_reset_timestamp(row["expected_reset_at"])
        except Exception:
            verbose_proxy_logger.debug(
                "OpenRouter durable quota check failed; failing open for alias selection",
                exc_info=True,
            )
            reset_at_ts = None

        if reset_at_ts is not None and reset_at_ts <= time.time():
            reset_at_ts = None
        _openrouter_free_daily_quota_cache = (
            reset_at_ts,
            time.monotonic() + _OPENROUTER_DURABLE_QUOTA_CACHE_TTL_SECONDS,
        )
        if reset_at_ts is None:
            return 0.0
        return max(0.0, reset_at_ts - time.time())


def _is_openrouter_free_quota_candidate(candidate: dict[str, Any]) -> bool:
    if candidate["provider"] != _CODEX_AUTO_AGENT_OPENROUTER_PROVIDER:
        return False
    model = str(candidate.get("model") or "")
    return model in _OPENROUTER_FREE_DAILY_QUOTA_MODELS


async def _apply_openrouter_durable_quota_candidate_cooldown(
    *,
    candidate: dict[str, Any],
    cooldown_seconds: float,
    cooldown_state_source: Optional[str],
    skip_reason: Optional[str],
) -> tuple[float, Optional[str], Optional[str]]:
    if not _is_openrouter_free_quota_candidate(candidate):
        return cooldown_seconds, cooldown_state_source, skip_reason

    durable_cooldown = await _get_openrouter_free_daily_quota_exhausted_cooldown_seconds()
    if durable_cooldown <= 0:
        return cooldown_seconds, cooldown_state_source, skip_reason

    if durable_cooldown > cooldown_seconds:
        cooldown_seconds = durable_cooldown
        cooldown_state_source = "durable_quota"
        skip_reason = "durable_quota_exhausted"
    return cooldown_seconds, cooldown_state_source, skip_reason


def _auto_agent_alias_float(value: Any) -> Optional[float]:
    if value is None:
        return None
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def _auto_agent_alias_int(value: Any) -> Optional[int]:
    if value is None:
        return None
    try:
        return int(value)
    except (TypeError, ValueError):
        return None


def _format_auto_agent_alias_timestamp(value: datetime) -> str:
    return value.astimezone(timezone.utc).isoformat().replace("+00:00", "Z")


def _auto_agent_alias_cooldown_until(
    cooldown_seconds: Optional[float],
) -> Optional[str]:
    if cooldown_seconds is None:
        return None
    return _format_auto_agent_alias_timestamp(
        datetime.now(timezone.utc) + timedelta(seconds=max(0.0, cooldown_seconds))
    )


def _extract_auto_agent_alias_session_id(
    request: Request,
    request_body: dict[str, Any],
) -> Optional[str]:
    metadata = request_body.get("litellm_metadata")
    if isinstance(metadata, dict):
        session_id = _clean_codex_auth_value(metadata.get("session_id"))
        if session_id is not None:
            return session_id
    passthrough_session_id = _extract_passthrough_session_id(request, request_body)
    if passthrough_session_id is not None:
        return passthrough_session_id
    headers = _safe_get_request_headers(request)
    for header_name in ("session_id", "session-id", "x-session-id"):
        header_value = _get_codex_auto_agent_header(headers, header_name)
        if header_value is not None:
            return header_value
    return None


def _extract_auto_agent_alias_metadata_value(
    request_body: dict[str, Any],
    *keys: str,
) -> Optional[str]:
    metadata = request_body.get("litellm_metadata")
    if not isinstance(metadata, dict):
        return None
    for key in keys:
        value = _clean_codex_auth_value(metadata.get(key))
        if value is not None:
            return value
    return None


def _normalize_auto_agent_alias_client_product(value: Any) -> Optional[str]:
    cleaned = _clean_codex_auth_value(value)
    if cleaned is None:
        return None
    product = cleaned.split()[0].strip("()")
    if not product:
        return None
    if "/" not in product:
        return product
    name, version = product.split("/", 1)
    normalized_name = name.lower().replace("_", "-")
    if normalized_name in {"codex", "codex-cli", "codex-tui", "codex-cli-rs"}:
        name = "Codex"
    elif normalized_name in {"claude", "claude-cli", "claude-code"}:
        name = "Claude"
    elif normalized_name in {"grok", "grok-build", "grok-pager"}:
        name = "Grok"
    return f"{name}/{version}"


def _extract_auto_agent_alias_client_product_label(
    request: Request,
    request_body: dict[str, Any],
) -> Optional[str]:
    metadata = request_body.get("litellm_metadata")
    if isinstance(metadata, dict):
        for key in (
            "client_name_version",
            "client_label",
            "client_user_agent",
            "user_agent",
        ):
            value = _normalize_auto_agent_alias_client_product(metadata.get(key))
            if value:
                return value
        name = _normalize_auto_agent_alias_client_product(metadata.get("client_name"))
        version = _clean_codex_auth_value(metadata.get("client_version"))
        if name and version and "/" not in name:
            return f"{name}/{version}"
        if name:
            return name
    headers = _safe_get_request_headers(request)
    for header_name in (
        "x-aawm-client",
        "x-litellm-client",
        "x-client-name-version",
        "user-agent",
    ):
        value = _normalize_auto_agent_alias_client_product(_get_codex_auto_agent_header(headers, header_name))
        if value:
            return value
    return None


def _extract_auto_agent_alias_incoming_endpoint(request: Request) -> str:
    parsed_url = urlparse(str(getattr(request, "url", "") or ""))
    path = parsed_url.path or getattr(request, "path", None) or "/"
    safe_pairs: list[tuple[str, str]] = []
    for key, value in parse_qsl(parsed_url.query, keep_blank_values=True):
        if key.lower() not in {"alt", "api-version", "beta", "stream"}:
            continue
        safe_key = _clean_codex_auth_value(key)
        safe_value = _clean_codex_auth_value(value)
        if safe_key and safe_value is not None:
            safe_pairs.append((safe_key, safe_value))
    if not safe_pairs:
        return path
    return f"{path}?{urlencode(safe_pairs)}"


def _resolve_auto_agent_alias_route_rollup_outgoing_target(
    *,
    route_family: Optional[str],
    target_url: Optional[Union[str, httpx.URL]] = None,
) -> Optional[str]:
    cleaned_route_family = _clean_codex_auth_value(route_family)
    if target_url is not None:
        return _get_anthropic_adapter_access_log_target_label(target_url)
    route_family_target_labels = {
        "codex_opencode_zen_adapter": "opencode.ai/zen/v1/chat/completions",
        "codex_openrouter_completion_adapter": "openrouter.ai/api/v1/chat/completions",
        "anthropic_opencode_zen_responses_adapter": "opencode.ai/zen/v1/responses",
        "anthropic_opencode_zen_completion_adapter": "opencode.ai/zen/v1/chat/completions",
    }
    return route_family_target_labels.get(cleaned_route_family or "", cleaned_route_family)


def _build_adapted_route_rollup_kwargs(
    litellm_metadata: dict[str, Any],
) -> dict[str, Any]:
    return {
        "litellm_params": {
            "metadata": dict(litellm_metadata),
        }
    }


def _emit_adapted_route_access_log(
    *,
    request: Request,
    target_url: str,
    request_body: dict[str, Any],
    rollup_kwargs: dict[str, Any],
    adapter_label: str,
) -> None:
    try:
        emit_aawm_route_access_log(
            request=request,
            target=target_url,
            request_body=request_body,
            kwargs=rollup_kwargs,
        )
    except Exception:
        verbose_proxy_logger.debug(
            "Failed to emit AAWM route access log for %s adapter",
            adapter_label,
            exc_info=True,
        )


def _record_adapted_completed_route_rollup_turn(
    rollup_kwargs: dict[str, Any],
    *,
    adapter_label: str,
) -> None:
    try:
        record_aawm_route_rollup_turn(rollup_kwargs)
    except Exception:
        verbose_proxy_logger.debug(
            "Failed to record AAWM route rollup turn for %s adapter",
            adapter_label,
            exc_info=True,
        )


def _record_adapted_completed_route_rollup_after_stream(
    response: StreamingResponse,
    rollup_kwargs: dict[str, Any],
    *,
    adapter_label: str,
) -> StreamingResponse:
    original_iterator = response.body_iterator
    recorded = False

    async def _wrapped_iterator() -> Any:
        nonlocal recorded
        async for chunk in original_iterator:
            yield chunk
        if not recorded:
            recorded = True
            _record_adapted_completed_route_rollup_turn(
                rollup_kwargs,
                adapter_label=adapter_label,
            )

    response.body_iterator = _wrapped_iterator()
    return response


def _auto_agent_alias_model_rollup_label(event: dict[str, Any]) -> Optional[str]:
    model = _clean_codex_auth_value(event.get("model"))
    alias_model = _clean_codex_auth_value(event.get("alias_model"))
    if model and alias_model and model != alias_model:
        return f"{model}({alias_model})"
    return model or alias_model


def _auto_agent_alias_route_rollup_status(event: dict[str, Any]) -> Optional[str]:
    event_type = str(event.get("event_type") or "")
    candidate_status = str(event.get("candidate_status") or "")
    selection_reason = str(event.get("selection_reason") or "")
    failure_class = str(event.get("failure_class") or "")
    cooldown_scope = str(event.get("cooldown_scope") or "")
    if event_type == "no_candidate_available":
        return "Exhausted"
    if "auth_degraded" in candidate_status or "auth_degraded" in selection_reason:
        return "Degraded"
    # request-local / no-cooldown failures must not look like durable cool-downs.
    # Note: do not substring-match "cooldown" — retryable_no_cooldown contains it.
    if candidate_status == "retryable_no_cooldown" or cooldown_scope == "none":
        if event.get("error_status_code") or failure_class:
            return "Failed"
        return None
    if cooldown_scope == "request_local":
        if event.get("error_status_code") or failure_class or event.get("redispatch_required"):
            return "Failed"
        return None
    if candidate_status in {
        "cooldown_set",
        "terminal_in_flight_cooldown_set",
        "skipped_cooldown",
    } or (
        candidate_status.startswith("skipped_")
        and "cooldown" in candidate_status
        and "auth_degraded" not in candidate_status
    ):
        return "Cooling Down"
    if cooldown_scope == "candidate" or (event.get("redispatch_required") and cooldown_scope != "request_local"):
        return "Cooling Down"
    if failure_class in {"rate_limited", "capacity_exhausted", "transient_error"}:
        return "Cooling Down"
    if event.get("error_status_code") or failure_class:
        return "Failed"
    return None


def _auto_agent_alias_route_status_message(event: dict[str, Any]) -> str:
    parts: list[str] = []
    source_error = _clean_codex_auth_value(event.get("source_error"))
    if source_error is not None:
        parts.append(f"source_error={source_error}")
    for key in (
        "failure_class",
        "error_type",
        "error_code",
        "error_status_code",
        "candidate_status",
        "selection_reason",
    ):
        value = event.get(key)
        if value is not None:
            parts.append(f"{key}={value}")
    error_tokens = event.get("error_tokens")
    if isinstance(error_tokens, list) and error_tokens:
        parts.append("error_tokens={}".format(",".join(str(v) for v in error_tokens[:5])))
    return "; ".join(parts) or "route status changed"


def _resolve_auto_agent_alias_route_host_attribution(
    request: Request,
) -> dict[str, Optional[str]]:
    """Non-blocking host attribution for sync audit/event builders (RR-054 #4).

    Reverse-DNS is never performed inline on the event loop: the shared resolver
    defaults to ``allow_blocking_lookup=False`` and schedules background enrichment.
    Async request paths that need a full lookup should await
    ``_aresolve_auto_agent_alias_route_host_attribution``.
    """
    try:
        return resolve_aawm_route_host_attribution(
            request,
            allow_blocking_lookup=False,
        )
    except Exception:
        return {
            "client_ip": None,
            "client_ip_source": None,
            "host_name": None,
            "host_name_source": None,
        }


async def _aresolve_auto_agent_alias_route_host_attribution(
    request: Request,
) -> dict[str, Optional[str]]:
    """Async host attribution that offloads DNS via aresolve (RR-054 #4)."""
    try:
        return await aresolve_aawm_route_host_attribution(
            request,
            allow_blocking_lookup=True,
        )
    except Exception:
        return {
            "client_ip": None,
            "client_ip_source": None,
            "host_name": None,
            "host_name_source": None,
        }


def _build_auto_agent_alias_rollup_group_header_label(
    *,
    repository: Optional[str],
    client_product_label: Optional[str],
    host_name: Optional[str],
) -> Optional[str]:
    return build_aawm_route_rollup_group_header_label(
        repository=repository,
        client_product_label=client_product_label,
        host_name=host_name,
    )


def _resolve_auto_agent_alias_route_rollup_group_header_label(
    event: dict[str, Any],
) -> Optional[str]:
    group_header_label = _clean_codex_auth_value(event.get("rollup_group_header_label"))
    if not group_header_label:
        return None
    host_name = _clean_codex_auth_value(event.get("host_name"))
    if "@" in group_header_label or not host_name:
        return group_header_label
    return f"{group_header_label}@{host_name}"


def _record_auto_agent_alias_route_status_rollup(event: dict[str, Any]) -> None:
    status = _auto_agent_alias_route_rollup_status(event)
    if status is None:
        return
    alias_model = _clean_codex_auth_value(event.get("alias_model"))
    model_labels: list[str] = []
    model_label = _auto_agent_alias_model_rollup_label(event)
    if model_label:
        model_labels.append(model_label)
    candidates = event.get("candidates")
    if isinstance(candidates, list):
        for candidate in candidates:
            if not isinstance(candidate, dict):
                continue
            candidate_model = _clean_codex_auth_value(candidate.get("model"))
            if candidate_model and alias_model and candidate_model != alias_model:
                candidate_model = f"{candidate_model}({alias_model})"
            if candidate_model and candidate_model not in model_labels:
                model_labels.append(candidate_model)
    if not model_labels:
        return

    message = _auto_agent_alias_route_status_message(event)
    for label in model_labels:
        emit_aawm_route_status_event(
            alias_model=alias_model,
            model_label=label.split("(", 1)[0],
            status=status,
            message=message,
        )

    group_header_label = _resolve_auto_agent_alias_route_rollup_group_header_label(event)
    incoming_endpoint = _clean_codex_auth_value(event.get("incoming_endpoint"))
    outgoing_target = (
        _clean_codex_auth_value(event.get("outgoing_target"))
        or _resolve_auto_agent_alias_route_rollup_outgoing_target(
            route_family=_clean_codex_auth_value(event.get("route_family")),
            target_url=event.get("target_url"),
        )
        or "candidate_selection"
    )
    if not group_header_label or not incoming_endpoint:
        return
    for label in model_labels:
        record_aawm_route_rollup(
            group_header_label=group_header_label,
            incoming_endpoint=incoming_endpoint,
            outgoing_target=outgoing_target,
            model_label=label,
            turns=0,
            status=status,
            message=_clean_codex_auth_value(event.get("source_error")),
        )


def _emit_auto_agent_alias_route_event(
    event: dict[str, Any],
    *,
    level: str = "info",
) -> None:
    _record_auto_agent_alias_route_status_rollup(event)
    if not (_aawm_alias_route_verbose_json_enabled() or _aawm_alias_route_healthy_json_enabled()):
        return
    if not _should_emit_auto_agent_alias_route_event(event, level=level):
        return
    log_payload = {"event": "aawm_alias_route", **event}
    message = "AAWM_ALIAS_ROUTE: {}".format(json.dumps(log_payload, sort_keys=True, default=str, separators=(",", ":")))
    verbose_aawm_route_logger.info(message)


def _should_emit_auto_agent_alias_route_event(
    event: dict[str, Any],
    *,
    level: str = "info",
) -> bool:
    if level == "warning":
        return True

    if _aawm_alias_route_healthy_json_enabled():
        return True

    if event.get("failure_class") or event.get("error_status_code"):
        return True
    if event.get("redispatch_required") or event.get("redispatch_threshold_crossed"):
        return True

    event_type = str(event.get("event_type") or "")
    candidate_status = str(event.get("candidate_status") or "")
    if event_type in {
        "candidate_attempt_started",
        "candidate_selected",
    }:
        return False
    if candidate_status in {"started", "selected"}:
        return False
    if event.get("selection_reason") == "session_affinity":
        return False
    return True


_AUTO_AGENT_ROLE_DECLARATION_RE = re.compile(
    r"^[ \t]*You are a '(?P<agent>explorer|worker|default)' agent\.[ \t]*$",
    re.MULTILINE,
)
_AUTO_AGENT_KNOWN_ROLE_NAMES = frozenset({"explorer", "worker", "default"})
_AUTO_AGENT_PRIOR_TOOL_ITEM_TYPES = frozenset(
    {
        "function_call",
        "function_call_output",
        "tool_use",
        "tool_result",
        "mcp_call",
        "mcp_tool_call",
        "mcp_approval_request",
        "mcp_approval_response",
    }
)
_AUTO_AGENT_FILE_EDIT_TOOL_NAMES = frozenset(
    {
        "apply_patch",
        "create_file",
        "edit_file",
        "multi_replace_file_content",
        "replace_file_content",
        "write_file",
    }
)
_AUTO_AGENT_REQUEST_CALL_ID_STATE_KEY = "aawm_alias_request_litellm_call_id"
_AUTO_AGENT_REQUEST_CONTEXT_STATE_KEY = "aawm_alias_request_context"


def _extract_auto_agent_alias_text_blobs(request_body: dict[str, Any]) -> list[str]:
    blobs: list[str] = []
    for key in ("instructions", "system"):
        value = request_body.get(key)
        if isinstance(value, str) and value.strip():
            blobs.append(value)
        elif isinstance(value, list):
            parts: list[str] = []
            for item in value:
                if isinstance(item, str) and item.strip():
                    parts.append(item)
                elif isinstance(item, dict):
                    text = item.get("text") or item.get("content")
                    if isinstance(text, str) and text.strip():
                        parts.append(text)
            if parts:
                blobs.append("\n".join(parts))
    messages = request_body.get("messages")
    if isinstance(messages, list):
        for message in messages[:5]:
            if not isinstance(message, dict):
                continue
            role = str(message.get("role") or "").lower()
            if role not in {"system", "developer"}:
                continue
            content = message.get("content")
            if isinstance(content, str) and content.strip():
                blobs.append(content)
            elif isinstance(content, list):
                parts = []
                for block in content:
                    if isinstance(block, dict):
                        text = block.get("text") or block.get("content")
                        if isinstance(text, str) and text.strip():
                            parts.append(text)
                    elif isinstance(block, str) and block.strip():
                        parts.append(block)
                if parts:
                    blobs.append("\n".join(parts))
    return blobs


def _extract_auto_agent_alias_role_from_text(text: str) -> Optional[str]:
    if not isinstance(text, str) or not text:
        return None
    match = _AUTO_AGENT_ROLE_DECLARATION_RE.search(text)
    if not match:
        return None
    role = _clean_codex_auth_value(match.group("agent"))
    if role is None:
        return None
    normalized = role.lower()
    return normalized if normalized in _AUTO_AGENT_KNOWN_ROLE_NAMES else None


def _infer_auto_agent_alias_role_from_request_body(
    request_body: dict[str, Any],
) -> Optional[str]:
    for blob in _extract_auto_agent_alias_text_blobs(request_body):
        role = _extract_auto_agent_alias_role_from_text(blob)
        if role is not None:
            return role
    return None


def _iter_auto_agent_alias_metadata_dicts(
    request: Request,
    request_body: dict[str, Any],
) -> list[dict[str, Any]]:
    sources: list[dict[str, Any]] = []
    for candidate in (
        request_body.get("litellm_metadata"),
        request_body.get("metadata"),
        request_body.get("source"),
    ):
        if isinstance(candidate, dict):
            sources.append(candidate)
            nested_source = candidate.get("source")
            if isinstance(nested_source, dict):
                sources.append(nested_source)
    headers = _safe_get_request_headers(request)
    if isinstance(headers, dict) and headers:
        # RR-054 #56: only trusted/low-cardinality header keys may influence identity fields.
        allowed = {
            "x-aawm-agent-id",
            "x-aawm-agent-name",
            "x-aawm-agent-role",
            "x-aawm-dispatch-id",
            "x-aawm-session-id",
            "x-session-id",
            "session_id",
            "session-id",
            "x-litellm-session-id",
        }
        filtered = {key: value for key, value in headers.items() if isinstance(key, str) and key.lower() in allowed}
        if filtered:
            sources.append(filtered)
    return sources


def _extract_auto_agent_alias_agent_dispatch_fields(
    request: Request,
    request_body: dict[str, Any],
) -> dict[str, Any]:
    """Extract explicit agent/dispatch fields with role-declaration fallback.

    Prefer structured metadata when present. Fall back only to the exact
    profile sentence form: ``You are a '<role>' agent.`` for explorer/worker/default.
    """
    fields: dict[str, Any] = {}
    sources = _iter_auto_agent_alias_metadata_dicts(request, request_body)

    def _first_from_sources(*keys: str) -> Optional[str]:
        for source in sources:
            for key in keys:
                value = _clean_codex_auth_value(source.get(key))
                if value is not None:
                    return value
        return None

    agent_name = _first_from_sources(
        "agent_name",
        "aawm_agent_name",
        "aawm_claude_agent_name",
        "codex_agent_name",
    )
    agent_role = _first_from_sources(
        "agent_role",
        "aawm_agent_role",
        "codex_agent_role",
        "agent_nickname",
    )
    agent_id = _first_from_sources(
        "agent_id",
        "aawm_agent_id",
        "codex_agent_id",
        "claude_agent_id",
        "subagent_id",
        "source_agent_id",
    )
    thread_source = _first_from_sources(
        "thread_source",
        "aawm_thread_source",
        "codex_thread_source",
    )
    redispatch_ordinal: Optional[Union[int, str]] = None
    for source in sources:
        for key in (
            "redispatch_ordinal",
            "agent_redispatch_ordinal",
            "dispatch_ordinal",
            "aawm_redispatch_ordinal",
        ):
            raw = source.get(key)
            if raw is None or raw == "":
                continue
            try:
                redispatch_ordinal = int(raw)
            except (TypeError, ValueError):
                redispatch_ordinal = _clean_codex_auth_value(raw)
            if redispatch_ordinal is not None:
                break
        if redispatch_ordinal is not None:
            break
    dispatch_id = _first_from_sources(
        "dispatch_id",
        "agent_dispatch_id",
        "aawm_dispatch_id",
        "codex_dispatch_id",
    )
    agent_profile = _first_from_sources(
        "agent_profile",
        "aawm_agent_profile",
        "codex_agent_profile",
    )

    inferred_role = (
        _infer_auto_agent_alias_role_from_request_body(request_body)
        if agent_name is None or agent_role is None
        else None
    )
    if inferred_role is not None:
        if agent_role is None:
            agent_role = inferred_role
        if agent_name is None:
            agent_name = inferred_role
        if agent_profile is None:
            agent_profile = inferred_role
    if thread_source is None and inferred_role is not None:
        thread_source = "subagent"

    if agent_name is not None:
        fields["agent_name"] = agent_name
    if agent_role is not None:
        fields["agent_role"] = agent_role
    if agent_id is not None:
        fields["agent_id"] = agent_id
    if thread_source is not None:
        fields["thread_source"] = thread_source
    if redispatch_ordinal is not None:
        fields["redispatch_ordinal"] = redispatch_ordinal
    if dispatch_id is not None:
        fields["dispatch_id"] = dispatch_id
    if agent_profile is not None:
        fields["agent_profile"] = agent_profile
    return fields


def _walk_auto_agent_alias_prior_tool_activity(
    value: Any,
    *,
    tool_names: list[str],
    file_edit_tool_names: list[str],
    counters: dict[str, int],
    _seen: Optional[set[int]] = None,
) -> None:
    if isinstance(value, (dict, list)):
        if _seen is None:
            _seen = set()
        value_id = id(value)
        if value_id in _seen:
            return
        _seen.add(value_id)

    def _record_tool_name(name: Any, *, is_call: bool) -> None:
        if not isinstance(name, str) or not name.strip():
            return
        clean_name = name.strip()
        if clean_name not in tool_names:
            tool_names.append(clean_name)
        if not is_call:
            return
        normalized = clean_name.lower().replace("-", "_")
        short_name = re.split(r"[./:]", normalized)[-1]
        if short_name not in _AUTO_AGENT_FILE_EDIT_TOOL_NAMES:
            return
        counters["prior_file_edit_tool_call_count"] += 1
        if clean_name not in file_edit_tool_names:
            file_edit_tool_names.append(clean_name)

    if isinstance(value, dict):
        item_type = value.get("type")
        role = str(value.get("role") or "").lower()
        if isinstance(item_type, str) and item_type in _AUTO_AGENT_PRIOR_TOOL_ITEM_TYPES:
            # RR-054 #58: single membership test for call vs result item types.
            is_tool_call = item_type in {
                "function_call",
                "tool_use",
                "mcp_call",
                "mcp_tool_call",
                "mcp_approval_request",
            }
            if is_tool_call:
                counters["prior_tool_call_count"] += 1
            elif item_type in {
                "function_call_output",
                "tool_result",
                "mcp_approval_response",
            }:
                counters["prior_tool_result_count"] += 1
            name = value.get("name")
            if not isinstance(name, str) or not name:
                function_obj = value.get("function")
                if isinstance(function_obj, dict):
                    name = function_obj.get("name")
            _record_tool_name(name, is_call=is_tool_call)
        if role == "tool" or value.get("tool_call_id") or value.get("tool_calls"):
            if role == "tool" or value.get("tool_call_id"):
                counters["prior_tool_result_count"] += 1
            tool_calls = value.get("tool_calls")
            if isinstance(tool_calls, list):
                counters["prior_tool_call_count"] += len(tool_calls)
                for tool_call in tool_calls:
                    if not isinstance(tool_call, dict):
                        continue
                    name = tool_call.get("name")
                    function_obj = tool_call.get("function")
                    if not isinstance(name, str) or not name:
                        if isinstance(function_obj, dict):
                            name = function_obj.get("name")
                    _record_tool_name(name, is_call=True)
        for child in value.values():
            _walk_auto_agent_alias_prior_tool_activity(
                child,
                tool_names=tool_names,
                file_edit_tool_names=file_edit_tool_names,
                counters=counters,
                _seen=_seen,
            )
        return

    if isinstance(value, list):
        for item in value:
            _walk_auto_agent_alias_prior_tool_activity(
                item,
                tool_names=tool_names,
                file_edit_tool_names=file_edit_tool_names,
                counters=counters,
                _seen=_seen,
            )


def _summarize_auto_agent_alias_actual_prior_tool_activity(
    request_body: dict[str, Any],
) -> dict[str, Any]:
    """Conservative summary of actual prior tool activity in the request.

    Counts only concrete tool-call/result evidence already present in the
    request body. Continuation markers alone do not count as partial activity.
    """
    tool_names: list[str] = []
    file_edit_tool_names: list[str] = []
    counters = {
        "prior_tool_call_count": 0,
        "prior_tool_result_count": 0,
        "prior_file_edit_tool_call_count": 0,
    }
    for key in ("input", "messages", "content", "tools_results", "tool_results"):
        if key in request_body:
            _walk_auto_agent_alias_prior_tool_activity(
                request_body.get(key),
                tool_names=tool_names,
                file_edit_tool_names=file_edit_tool_names,
                counters=counters,
            )
    has_actual_prior_tool_activity = bool(counters["prior_tool_call_count"] or counters["prior_tool_result_count"])
    has_previous_response_id = bool(_clean_codex_auth_value(request_body.get("previous_response_id")))
    has_continuation_state = _codex_auto_agent_request_has_continuation_state(request_body)
    return {
        "has_actual_prior_tool_activity": has_actual_prior_tool_activity,
        "prior_tool_call_count": counters["prior_tool_call_count"],
        "prior_tool_result_count": counters["prior_tool_result_count"],
        "prior_tool_names": tool_names[:20],
        "has_prior_file_edit_activity": bool(counters["prior_file_edit_tool_call_count"]),
        "prior_file_edit_tool_call_count": counters["prior_file_edit_tool_call_count"],
        "prior_file_edit_tool_names": file_edit_tool_names[:20],
        "has_previous_response_id": has_previous_response_id,
        "has_continuation_state": bool(has_continuation_state),
    }


def _classify_auto_agent_alias_terminal_activity_status(
    prior_tool_activity_summary: Optional[dict[str, Any]],
) -> str:
    if isinstance(prior_tool_activity_summary, dict) and prior_tool_activity_summary.get(
        "has_actual_prior_tool_activity"
    ):
        return "failed_after_partial_activity"
    return "failed_no_activity"


def _get_or_create_auto_agent_alias_request_call_id(
    request: Request,
    request_body: dict[str, Any],
) -> str:
    """Return one stable call ID for all alias audit events in this request."""
    request_state = getattr(request, "state", None)
    if request_state is not None:
        existing = getattr(
            request_state,
            _AUTO_AGENT_REQUEST_CALL_ID_STATE_KEY,
            None,
        )
        if isinstance(existing, str) and existing.strip():
            return existing.strip()

    litellm_call_id = _extract_auto_agent_alias_metadata_value(
        request_body,
        "litellm_call_id",
        "call_id",
        "aawm_litellm_call_id",
    )
    if litellm_call_id is None:
        scope = request.scope if isinstance(getattr(request, "scope", None), dict) else {}
        for key in ("litellm_call_id", "call_id", "request_id"):
            value = _clean_codex_auth_value(scope.get(key))
            if value is not None:
                litellm_call_id = value
                break
    if litellm_call_id is None and request_state is not None:
        for key in ("litellm_call_id", "call_id", "request_id"):
            value = getattr(request_state, key, None)
            if not isinstance(value, str):
                continue
            cleaned = _clean_codex_auth_value(value)
            if cleaned is not None:
                litellm_call_id = cleaned
                break
    if litellm_call_id is None:
        headers = _safe_get_request_headers(request)
        if isinstance(headers, dict):
            for key in (
                "x-litellm-call-id",
                "litellm-call-id",
                "x-request-id",
            ):
                value = _clean_codex_auth_value(headers.get(key))
                if value is not None:
                    litellm_call_id = value
                    break
    if litellm_call_id is None:
        litellm_call_id = str(uuid4())

    if request_state is not None:
        setattr(
            request_state,
            _AUTO_AGENT_REQUEST_CALL_ID_STATE_KEY,
            litellm_call_id,
        )
    return litellm_call_id


class _AutoAgentAliasRequestContext(TypedDict):
    agent_dispatch: dict[str, Any]
    session_id: Optional[str]
    litellm_call_id: str
    trace_id: Optional[str]
    repository: Optional[str]
    client_product_label: Optional[str]
    host_attribution: dict[str, Optional[str]]
    rollup_group_header_label: Optional[str]
    prior_tool_activity_summary: NotRequired[dict[str, Any]]


def _normalize_auto_agent_alias_request_context(
    value: Mapping[str, object],
) -> _AutoAgentAliasRequestContext:
    agent_dispatch_value = value.get("agent_dispatch")
    host_attribution_value = value.get("host_attribution")
    context: _AutoAgentAliasRequestContext = {
        "agent_dispatch": (dict(agent_dispatch_value) if isinstance(agent_dispatch_value, dict) else {}),
        "session_id": _clean_optional_string(value.get("session_id")),
        "litellm_call_id": _clean_optional_string(value.get("litellm_call_id")) or str(uuid4()),
        "trace_id": _clean_optional_string(value.get("trace_id")),
        "repository": _clean_optional_string(value.get("repository")),
        "client_product_label": _clean_optional_string(value.get("client_product_label")),
        "host_attribution": (
            {str(key): item if isinstance(item, str) else None for key, item in host_attribution_value.items()}
            if isinstance(host_attribution_value, dict)
            else {}
        ),
        "rollup_group_header_label": _clean_optional_string(value.get("rollup_group_header_label")),
    }
    prior_activity = value.get("prior_tool_activity_summary")
    if isinstance(prior_activity, dict):
        context["prior_tool_activity_summary"] = dict(prior_activity)
    return context


def _clean_optional_string(value: object) -> Optional[str]:
    return _clean_secret_string(value if isinstance(value, str) else None)


def _get_auto_agent_alias_request_context(
    request: Request,
    request_body: Payload,
    *,
    include_activity: bool = False,
) -> _AutoAgentAliasRequestContext:
    request_state = getattr(request, "state", None)
    cached_value = (
        getattr(request_state, _AUTO_AGENT_REQUEST_CONTEXT_STATE_KEY, None) if request_state is not None else None
    )
    if isinstance(cached_value, dict):
        cached = _normalize_auto_agent_alias_request_context(cached_value)
    else:
        repository = _extract_auto_agent_alias_metadata_value(
            request_body,
            "repository",
            "repo",
            "repo_name",
            "repository_name",
        )
        client_product_label = _extract_auto_agent_alias_client_product_label(
            request,
            request_body,
        )
        host_attribution = _resolve_auto_agent_alias_route_host_attribution(request)
        cached = {
            "agent_dispatch": _extract_auto_agent_alias_agent_dispatch_fields(
                request,
                request_body,
            ),
            "session_id": _extract_auto_agent_alias_session_id(
                request,
                request_body,
            ),
            "litellm_call_id": _get_or_create_auto_agent_alias_request_call_id(
                request,
                request_body,
            ),
            "trace_id": _extract_auto_agent_alias_metadata_value(
                request_body,
                "trace_id",
                "langfuse_trace_id",
                "aawm_trace_id",
            ),
            "repository": repository,
            "client_product_label": client_product_label,
            "host_attribution": host_attribution,
            "rollup_group_header_label": (
                _build_auto_agent_alias_rollup_group_header_label(
                    repository=repository,
                    client_product_label=client_product_label,
                    host_name=host_attribution.get("host_name"),
                )
            ),
        }
        if request_state is not None:
            setattr(request_state, _AUTO_AGENT_REQUEST_CONTEXT_STATE_KEY, cached)
    if include_activity and "prior_tool_activity_summary" not in cached:
        cached["prior_tool_activity_summary"] = _summarize_auto_agent_alias_actual_prior_tool_activity(request_body)
    if request_state is not None:
        setattr(request_state, _AUTO_AGENT_REQUEST_CONTEXT_STATE_KEY, cached)
    return cached


def _attach_auto_agent_alias_terminal_context_fields(
    event: dict[str, Any],
    *,
    request: Request,
    request_body: dict[str, Any],
    selection: Optional[dict[str, Any]] = None,
    candidate: Optional[dict[str, Any]] = None,
    include_activity_status: bool = False,
) -> dict[str, Any]:
    """Attach direct context IDs, agent/dispatch fields, and activity summary."""
    needs_activity = include_activity_status or event.get("event_type") in {
        "no_candidate_available",
        "redispatch_required",
        "agent_session_terminated",
    }
    context = _get_auto_agent_alias_request_context(
        request,
        request_body,
        include_activity=needs_activity,
    )
    agent_dispatch = context["agent_dispatch"]
    for key, value in agent_dispatch.items():
        if value is not None and event.get(key) is None:
            event[key] = value

    # Prefer existing agent_id extraction when structured fields omit it.
    if event.get("agent_id") is None:
        agent_id = _extract_auto_agent_alias_metadata_value(
            request_body,
            "agent_id",
            "aawm_agent_id",
            "codex_agent_id",
            "claude_agent_id",
        )
        if agent_id is not None:
            event["agent_id"] = agent_id

    if event.get("session_id") is None:
        event["session_id"] = context.get("session_id")

    if event.get("litellm_call_id") is None:
        event["litellm_call_id"] = context.get("litellm_call_id")

    trace_id = context.get("trace_id")
    if trace_id is not None and event.get("trace_id") is None:
        event["trace_id"] = trace_id

    cooldown_state_source = None
    if isinstance(candidate, dict):
        cooldown_state_source = candidate.get("cooldown_state_source")
    if cooldown_state_source is None and isinstance(selection, dict):
        cooldown_state_source = selection.get("cooldown_state_source")
    if cooldown_state_source is not None and event.get("cooldown_state_source") is None:
        event["cooldown_state_source"] = cooldown_state_source

    # RR-054 #29: expensive full-body tool-activity walk only when terminal status
    # classification actually needs it (or explicit include flag).
    if needs_activity:
        prior_summary = context.get("prior_tool_activity_summary")
        event["actual_prior_tool_activity_summary"] = prior_summary
    if include_activity_status:
        event["terminal_activity_status"] = _classify_auto_agent_alias_terminal_activity_status(prior_summary)
    return event


def _persist_auto_agent_alias_audit_only_events_best_effort(  # noqa: PLR0915
    events: list[dict[str, Any]],
    *,
    request_body: Optional[dict[str, Any]] = None,
) -> str:
    """Best-effort audit-only persistence without session_history inserts.

    Used for terminal/no-candidate Codex+Anthropic alias events that never reach
    a normal success/fallback write path. Failures are swallowed so routing is
    never blocked by observability.
    """
    if not events:
        return "skip_empty"

    max_event_types_for_log = 8

    def _sanitize_identifier(value: Any) -> str:
        if not isinstance(value, str) or not value.strip():
            return "<missing>"
        try:
            digest = hashlib.sha256(value.encode("utf-8")).hexdigest()[:12]
        except Exception:
            digest = "<redacted>"
        return digest

    def _sanitize_log_label(value: Any, *, max_length: int) -> str:
        if not isinstance(value, str) or not value.strip():
            return "<missing>"
        sanitized = re.sub(
            r"[^A-Za-z0-9_.:/-]+",
            "_",
            value.strip(),
        )
        return sanitized[:max_length] or "<missing>"

    def _collect_event_types() -> str:
        event_types: list[str] = []
        omitted_count = 0
        for event in events:
            event_type = event.get("event_type") if isinstance(event, dict) else None
            if not isinstance(event_type, str):
                continue
            sanitized = _sanitize_log_label(event_type, max_length=64)
            if sanitized in event_types:
                continue
            if len(event_types) >= max_event_types_for_log:
                omitted_count += 1
                continue
            event_types.append(sanitized)
        if omitted_count:
            event_types.append(f"+{omitted_count}_more")
        return f"[{','.join(event_types)}]"

    primary = events[-1] if isinstance(events[-1], dict) else {}
    metadata: dict[str, Any] = {
        "aawm_alias_routing_audit_only": True,
        "source": "auto_agent_alias_terminal_or_no_candidate",
    }
    if isinstance(request_body, dict):
        litellm_metadata = request_body.get("litellm_metadata")
        if isinstance(litellm_metadata, dict):
            for key in (
                "requested_model_alias",
                "model_alias_label",
                "repository",
            ):
                value = litellm_metadata.get(key)
                if value is not None:
                    metadata[key] = value

    event_types = _collect_event_types()
    alias = _sanitize_log_label(
        primary.get("alias_model")
        or primary.get("requested_model_alias")
        or metadata.get("requested_model_alias")
        or metadata.get("model_alias_label"),
        max_length=96,
    )
    session_id_hash = _sanitize_identifier(primary.get("session_id"))
    litellm_call_id_hash = _sanitize_identifier(primary.get("litellm_call_id"))
    trace_id_hash = _sanitize_identifier(primary.get("trace_id"))

    try:
        from litellm.integrations.aawm_agent_identity import (
            _build_alias_routing_audit_only_record,
            _enqueue_session_history_record,
            _spool_session_history_records,
        )
    except Exception as import_exc:
        verbose_proxy_logger.warning(
            "AAWM_ALIAS_ROUTE: unable to import alias routing audit-only helpers "
            "(persistence_disposition=fail_import, exception_class=%s, alias=%s, "
            "session_id_hash=%s, litellm_call_id_hash=%s, event_types=%s, "
            "event_count=%d)",
            type(import_exc).__name__,
            alias,
            session_id_hash,
            litellm_call_id_hash,
            event_types,
            len(events),
        )
        return "fail_import"

    try:
        record = _build_alias_routing_audit_only_record(
            events=events,
            session_id=primary.get("session_id"),
            litellm_call_id=primary.get("litellm_call_id"),
            model=primary.get("model") or primary.get("alias_model"),
            provider=primary.get("provider"),
            metadata=metadata,
        )
    except Exception as build_exc:
        verbose_proxy_logger.warning(
            "AAWM_ALIAS_ROUTE: failed to build alias routing audit-only record "
            "(persistence_disposition=fail_build, exception_class=%s, alias=%s, "
            "session_id_hash=%s, litellm_call_id_hash=%s, event_types=%s, "
            "event_count=%d)",
            type(build_exc).__name__,
            alias,
            session_id_hash,
            litellm_call_id_hash,
            event_types,
            len(events),
        )
        return "fail_build"

    try:
        _spool_session_history_records(
            [record],
            reason="alias audit terminal write-ahead",
        )
        return "spool_only"
    except Exception as spool_exc:
        verbose_proxy_logger.warning(
            "AAWM_ALIAS_ROUTE: failed to spool terminal alias audit event; "
            "queue_disposition=spool_failed, alias=%s, session_id_hash=%s, "
            "litellm_call_id_hash=%s, trace_id_hash=%s, event_types=%s, "
            "event_count=%d, exception_class=%s",
            alias,
            session_id_hash,
            litellm_call_id_hash,
            trace_id_hash,
            event_types,
            len(events),
            type(spool_exc).__name__,
        )
        try:
            _enqueue_session_history_record(record)
        except Exception as enqueue_exc:
            verbose_proxy_logger.warning(
                "AAWM_ALIAS_ROUTE: failed terminal alias audit fallback enqueue; "
                "queue_disposition=enqueue_failed, alias=%s, session_id_hash=%s, "
                "litellm_call_id_hash=%s, event_types=%s, event_count=%d, "
                "spool_exception_class=%s, enqueue_exception_class=%s",
                alias,
                session_id_hash,
                litellm_call_id_hash,
                event_types,
                len(events),
                type(spool_exc).__name__,
                type(enqueue_exc).__name__,
            )
            return "spool_enqueue_failed"
        return "spool_fallback_enqueue"


def _enrich_auto_agent_alias_terminal_event_from_attempts(
    event: dict[str, Any],
    attempts: Optional[list[dict[str, Any]]],
) -> list[dict[str, Any]]:
    normalized_attempts = [attempt for attempt in attempts or [] if isinstance(attempt, dict)]
    if not normalized_attempts:
        return normalized_attempts

    event["attempt_count"] = len(normalized_attempts)
    event["attempts"] = copy.deepcopy(normalized_attempts)
    last_attempt = normalized_attempts[-1]
    last_failure_class = last_attempt.get("error_class")
    if last_failure_class is not None:
        event["failure_class"] = last_failure_class
    event["attempted_provider_call"] = any(
        attempt.get("attempted_provider_call") is True for attempt in normalized_attempts
    )
    if event["attempted_provider_call"]:
        event["failure_phase"] = "provider_attempt"
    for key in (
        "provider",
        "model",
        "route_family",
        "source_error",
        "error_type",
        "error_code",
    ):
        value = last_attempt.get(key)
        if value is not None:
            event[key] = value
    return normalized_attempts


def _emit_auto_agent_alias_no_candidate_event(
    *,
    alias_family: str,
    alias_model: str,
    request: Request,
    request_body: dict[str, Any],
    exc: HTTPException,
    attempts: Optional[list[dict[str, Any]]] = None,
) -> None:
    detail: dict[str, Any] = exc.detail if isinstance(exc.detail, dict) else {}
    candidates = detail.get("candidates") if isinstance(detail, dict) else None
    context = _get_auto_agent_alias_request_context(
        request,
        request_body,
        include_activity=True,
    )
    repository = context.get("repository")
    client_product_label = context.get("client_product_label")
    host_attribution = context["host_attribution"]
    if alias_family.startswith("anthropic"):
        session_key = _resolve_anthropic_auto_agent_session_key(
            request,
            request_body,
            alias_model=alias_model,
        )
    else:
        session_key = _resolve_codex_auto_agent_session_key(
            request,
            request_body,
            alias_model=alias_model,
        )
    event = {
        "observed_at": _format_auto_agent_alias_timestamp(datetime.now(timezone.utc)),
        "alias_family": alias_family,
        "alias_model": alias_model,
        "session_id": context.get("session_id"),
        "session_key": session_key,
        "agent_id": _extract_auto_agent_alias_metadata_value(
            request_body,
            "agent_id",
            "aawm_agent_id",
            "codex_agent_id",
            "claude_agent_id",
        ),
        "repository": repository,
        "client_product_label": client_product_label,
        "client_ip": host_attribution.get("client_ip"),
        "client_ip_source": host_attribution.get("client_ip_source"),
        "host_name": host_attribution.get("host_name"),
        "host_name_source": host_attribution.get("host_name_source"),
        "rollup_group_header_label": context.get("rollup_group_header_label"),
        "incoming_endpoint": _extract_auto_agent_alias_incoming_endpoint(request),
        "outgoing_target": "candidate_selection",
        "event_type": "no_candidate_available",
        "candidate_status": "all_candidates_unavailable",
        "failure_phase": "candidate_selection",
        "attempted_provider_call": False,
        "error_status_code": exc.status_code,
        "candidate_count": len(candidates) if isinstance(candidates, list) else 0,
        "candidates": candidates if isinstance(candidates, list) else None,
    }
    _attach_auto_agent_alias_terminal_context_fields(
        event,
        request=request,
        request_body=request_body,
        include_activity_status=True,
    )
    normalized_attempts = _enrich_auto_agent_alias_terminal_event_from_attempts(
        event,
        attempts,
    )
    event["terminal_outcome"] = "agent_session_terminated"
    event["fallback_result"] = "no_candidate_available"
    event["redispatch_required"] = False
    event["agent_session_killed"] = True
    try:
        from litellm.proxy.aawm_runtime_error_logging import (
            persist_agent_terminal_error,
        )

        last_attempt = normalized_attempts[-1] if normalized_attempts else {}
        persist_terminal_error = partial(
            persist_agent_terminal_error,
            error_context={
                **event,
                "endpoint": event.get("incoming_endpoint"),
                "status_code": event.get("error_status_code"),
                "model_alias": alias_model,
                "provider": last_attempt.get("provider"),
                "model": last_attempt.get("model"),
                "route_family": last_attempt.get("route_family"),
                "failure_kind": "agent_alias_no_candidate",
                "error_code": event.get("failure_class") or "all_candidates_unavailable",
            },
            terminal_outcome="agent_session_terminated",
            fallback_result="no_candidate_available",
            redispatch_required=False,
            agent_session_killed=True,
        )
        # RR-054 #42: avoid blocking the event loop on JSONL intake I/O.
        try:
            loop = asyncio.get_running_loop()
        except RuntimeError:
            loop = None
        if loop is not None:
            loop.run_in_executor(
                None,
                persist_terminal_error,
            )
        else:
            persist_terminal_error()
    except Exception:
        verbose_proxy_logger.debug(
            "Failed to append terminal alias error intake",
            exc_info=True,
        )
    _emit_auto_agent_alias_route_event(
        event,
        level="warning",
    )
    # Terminal no-candidate outcomes never complete a normal provider write path.
    # Persist audit rows only so partial-activity vs no-op failures remain queryable.
    audit_events: list[dict[str, Any]] = []
    if normalized_attempts:
        last_attempt = normalized_attempts[-1]
        audit_events.extend(
            _build_auto_agent_alias_audit_events(
                alias_family=alias_family,
                alias_model=alias_model,
                request=request,
                request_body=request_body,
                selection={
                    "candidate": last_attempt,
                    "session_key": event.get("session_key"),
                    "lane_key": last_attempt.get("lane_key"),
                    "selection_reason": last_attempt.get("reason"),
                    "skipped": [],
                },
                attempts=normalized_attempts,
            )
        )
    audit_events.append(event)
    _persist_auto_agent_alias_audit_only_events_best_effort(
        audit_events,
        request_body=request_body,
    )


def _is_auto_agent_alias_in_flight_cooldown_http_exception(
    exc: HTTPException,
) -> bool:
    detail: dict[str, Any] = exc.detail if isinstance(exc.detail, dict) else {}
    error = detail.get("error") if isinstance(detail, dict) else None
    error_code = error.get("code") if isinstance(error, dict) else None
    return bool(detail.get("redispatch_required")) or error_code in {
        "aawm_codex_auto_agent_in_flight_provider_cooling_down",
        "aawm_anthropic_auto_agent_in_flight_provider_cooling_down",
        "aawm_codex_auto_agent_redispatch_required",
        "aawm_anthropic_auto_agent_redispatch_required",
    }


def _build_auto_agent_alias_audit_event(
    *,
    alias_family: str,
    alias_model: str,
    request: Request,
    request_body: dict[str, Any],
    selection: dict[str, Any],
    candidate: dict[str, Any],
    event_type: str,
    candidate_status: str,
    attempt_number: Optional[int] = None,
    selected: bool = False,
    skipped: bool = False,
    selection_reason: Optional[str] = None,
    lane_key: Optional[str] = None,
    cooldown_key: Optional[str] = None,
    cooldown_seconds: Optional[Any] = None,
    cooldown_scope: Optional[str] = None,
    failure_class: Optional[str] = None,
    error_status_code: Optional[Any] = None,
    error_type: Optional[str] = None,
    error_code: Optional[Any] = None,
    error_tokens: Optional[Any] = None,
    source_error: Optional[str] = None,
    retry_after_seconds: Optional[Any] = None,
    failure_phase: Optional[str] = None,
    attempted_provider_call: Optional[bool] = None,
    redispatch_required: bool = False,
) -> dict[str, Any]:
    normalized_cooldown_seconds = _auto_agent_alias_float(cooldown_seconds)
    if lane_key is None:
        lane_key = selection.get("lane_key")
    if cooldown_key is None and lane_key is not None:
        cooldown_key = _codex_auto_agent_candidate_key(candidate, lane_key)
    context = _get_auto_agent_alias_request_context(
        request,
        request_body,
    )
    repository = context.get("repository")
    client_product_label = context.get("client_product_label")
    host_attribution = context["host_attribution"]
    event: dict[str, Any] = {
        "observed_at": _format_auto_agent_alias_timestamp(datetime.now(timezone.utc)),
        "alias_family": alias_family,
        "alias_model": alias_model,
        "session_id": context.get("session_id"),
        "agent_id": _extract_auto_agent_alias_metadata_value(
            request_body,
            "agent_id",
            "aawm_agent_id",
            "codex_agent_id",
            "claude_agent_id",
        ),
        "repository": repository,
        "client_product_label": client_product_label,
        "client_ip": host_attribution.get("client_ip"),
        "client_ip_source": host_attribution.get("client_ip_source"),
        "host_name": host_attribution.get("host_name"),
        "host_name_source": host_attribution.get("host_name_source"),
        "rollup_group_header_label": context.get("rollup_group_header_label"),
        "incoming_endpoint": _extract_auto_agent_alias_incoming_endpoint(request),
        "outgoing_target": _resolve_auto_agent_alias_route_rollup_outgoing_target(
            route_family=candidate.get("route_family"),
            target_url=candidate.get("target_url"),
        ),
        "target_url": candidate.get("target_url"),
        "session_key": selection.get("session_key"),
        "provider": candidate.get("provider"),
        "model": candidate.get("model"),
        "route_family": candidate.get("route_family"),
        "lane_key": lane_key,
        "cooldown_key": cooldown_key,
        "attempt_number": attempt_number,
        "event_type": event_type,
        "selection_reason": selection_reason,
        "candidate_status": candidate_status,
        "failure_class": failure_class,
        "error_status_code": _auto_agent_alias_int(error_status_code),
        "error_type": error_type,
        "error_code": str(error_code) if error_code is not None else None,
        "source_error": _clean_codex_auth_value(source_error),
        "retry_after_seconds": _auto_agent_alias_float(retry_after_seconds),
        "failure_phase": failure_phase,
        "attempted_provider_call": attempted_provider_call,
        "cooldown_scope": cooldown_scope,
        "cooldown_seconds": (
            round(normalized_cooldown_seconds, 3) if normalized_cooldown_seconds is not None else None
        ),
        "cooldown_until": _auto_agent_alias_cooldown_until(normalized_cooldown_seconds),
        "selected": selected,
        "skipped": skipped,
        "last_resort": bool(candidate.get("last_resort")),
        "in_flight_session": bool(selection.get("in_flight_session")),
        "redispatch_required": redispatch_required,
        "redispatch_threshold_crossed": False,
    }
    if isinstance(error_tokens, list):
        event["error_tokens"] = error_tokens
    elif isinstance(error_tokens, set):
        event["error_tokens"] = sorted(error_tokens)

    cooldown_state_source = candidate.get("cooldown_state_source")
    if cooldown_state_source is None:
        cooldown_state_source = selection.get("cooldown_state_source")
    if cooldown_state_source is not None:
        event["cooldown_state_source"] = cooldown_state_source
    for field in _CODEX_AUTO_AGENT_REASONING_EFFORT_AUDIT_FIELDS:
        value = candidate.get(field)
        if value is not None:
            event[field] = value

    include_activity_status = (
        event_type
        in {
            "no_candidate_available",
            "redispatch_required",
            "candidate_retryable_failure",
        }
        or bool(redispatch_required)
        or (isinstance(error_status_code, int) and error_status_code == 429)
    )
    _attach_auto_agent_alias_terminal_context_fields(
        event,
        request=request,
        request_body=request_body,
        selection=selection,
        candidate=candidate,
        include_activity_status=include_activity_status,
    )
    return {key: value for key, value in event.items() if value is not None}


def _build_auto_agent_alias_audit_events(
    *,
    alias_family: str,
    alias_model: str,
    request: Request,
    request_body: dict[str, Any],
    selection: dict[str, Any],
    attempts: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    events: list[dict[str, Any]] = []
    skipped_candidates = selection.get("skipped")
    if isinstance(skipped_candidates, list):
        for skipped_candidate in skipped_candidates:
            if not isinstance(skipped_candidate, dict):
                continue
            reason = str(skipped_candidate.get("reason") or "cooldown")
            event_type = (
                "candidate_skipped_provider_degraded" if reason == "auth_degraded" else "candidate_skipped_cooldown"
            )
            events.append(
                _build_auto_agent_alias_audit_event(
                    alias_family=alias_family,
                    alias_model=alias_model,
                    request=request,
                    request_body=request_body,
                    selection=selection,
                    candidate=skipped_candidate,
                    event_type=event_type,
                    candidate_status=f"skipped_{reason}",
                    selected=False,
                    skipped=True,
                    selection_reason=reason,
                    lane_key=skipped_candidate.get("lane_key"),
                    cooldown_seconds=skipped_candidate.get("cooldown_seconds"),
                    failure_phase=skipped_candidate.get("failure_phase"),
                    attempted_provider_call=skipped_candidate.get("attempted_provider_call"),
                )
            )

    audit_attempts = attempts
    if not audit_attempts and isinstance(selection.get("candidate"), dict):
        audit_attempts = [
            _codex_auto_agent_candidate_public_shape(
                selection["candidate"],
                lane_key=selection.get("lane_key"),
                reason=selection.get("selection_reason"),
            )
        ]

    for index, attempt in enumerate(audit_attempts, start=1):
        if not isinstance(attempt, dict):
            continue
        status = str(attempt.get("status") or "").strip()
        failure_class = attempt.get("error_class")
        redispatch_required = status == "terminal_in_flight_cooldown_set"
        if redispatch_required:
            event_type = "redispatch_required"
        elif failure_class or status == "cooldown_set":
            event_type = "candidate_retryable_failure"
        else:
            event_type = "candidate_selected"
        events.append(
            _build_auto_agent_alias_audit_event(
                alias_family=alias_family,
                alias_model=alias_model,
                request=request,
                request_body=request_body,
                selection=selection,
                candidate=attempt,
                event_type=event_type,
                candidate_status=status or "selected",
                attempt_number=index,
                selected=True,
                skipped=False,
                selection_reason=attempt.get("reason") or selection.get("selection_reason"),
                lane_key=attempt.get("lane_key") or selection.get("lane_key"),
                # RR-054 #51: attach the attempt's own cooldown key (fall back to selection).
                cooldown_key=(
                    attempt.get("cooldown_key") or selection.get("cooldown_key")
                    if index == len(audit_attempts)
                    else attempt.get("cooldown_key")
                ),
                cooldown_seconds=attempt.get("cooldown_seconds"),
                cooldown_scope=attempt.get("cooldown_scope"),
                failure_class=failure_class,
                error_status_code=attempt.get("error_status_code"),
                error_type=attempt.get("error_type"),
                error_code=attempt.get("error_code"),
                error_tokens=attempt.get("error_tokens"),
                source_error=attempt.get("source_error"),
                retry_after_seconds=attempt.get("retry_after_seconds"),
                failure_phase=attempt.get("failure_phase"),
                attempted_provider_call=attempt.get("attempted_provider_call"),
                redispatch_required=redispatch_required,
            )
        )
    return events


def _codex_auto_agent_request_has_continuation_state(
    value: Any,
    _seen: Optional[set[int]] = None,
) -> bool:
    if isinstance(value, (dict, list)):
        if _seen is None:
            _seen = set()
        value_id = id(value)
        if value_id in _seen:
            return False
        _seen.add(value_id)

    if isinstance(value, dict):
        for key in (
            "previous_response_id",
            "call_id",
            "tool_call_id",
            "item_id",
        ):
            if value.get(key):
                return True
        item_type = value.get("type")
        if isinstance(item_type, str) and item_type in {
            "function_call",
            "function_call_output",
            "mcp_call",
            "mcp_approval_request",
            "mcp_approval_response",
            "reasoning",
            "tool_use",
            "tool_result",
        }:
            return True
        if value.get("role") == "tool":
            return True
        if value.get("tool_calls"):
            return True
        return any(_codex_auto_agent_request_has_continuation_state(child, _seen) for child in value.values())
    if isinstance(value, list):
        return any(_codex_auto_agent_request_has_continuation_state(item, _seen) for item in value)
    return False


def _raise_codex_auto_agent_in_flight_cooldown(
    *,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    cooldown_seconds: float,
) -> None:
    shaped_candidate = _codex_auto_agent_candidate_public_shape(
        candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        reason="in_flight_session_affinity_cooldown",
    )
    raise HTTPException(
        status_code=429,
        detail={
            "error": {
                "message": (
                    "Codex auto-agent alias target is cooling down for an in-flight "
                    "session; provider switching is disabled for stateful agent "
                    "continuations. Redispatch a fresh agent attempt to re-run the "
                    "auto selector."
                ),
                "type": "invalid_request_error",
                "code": "aawm_codex_auto_agent_in_flight_provider_cooling_down",
            },
            "candidate": shaped_candidate,
        },
        headers={"Retry-After": str(int(max(1.0, cooldown_seconds)))},
    )


def _build_auto_agent_redispatch_http_exception_detail(
    *,
    alias_family: str,
    alias_model: str,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    cooldown_seconds: float,
    error_tokens: set[str],
    error_class: Optional[str] = None,
    cooldown_scope: Optional[str] = None,
    error_status_code: Optional[Any] = None,
    error_type: Optional[str] = None,
    error_code: Optional[Any] = None,
    retry_after_seconds: Optional[Any] = None,
    failure_phase: Optional[str] = None,
    attempted_provider_call: Optional[bool] = None,
    audit_events: Optional[list[dict[str, Any]]] = None,
    attempts: Optional[list[dict[str, Any]]] = None,
    skipped_candidates: Optional[list[dict[str, Any]]] = None,
    code: str,
    message: str,
) -> dict[str, Any]:
    retry_after = int(
        max(
            1.0,
            float(retry_after_seconds) if retry_after_seconds is not None else cooldown_seconds,
        )
    )
    shaped_candidate = _codex_auto_agent_candidate_public_shape(
        candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        reason="in_flight_retryable_provider_exhaustion",
    )
    detail: dict[str, Any] = {
        "error": {
            "message": message,
            "type": "rate_limit_error",
            "code": code,
        },
        "alias_family": alias_family,
        "alias_model": alias_model,
        "redispatch_model": alias_model,
        "redispatch_reason": "in_flight_retryable_provider_exhaustion",
        "redispatch_required": True,
        "selected_provider": candidate.get("provider"),
        "selected_model": candidate.get("model"),
        "selected_route_family": candidate.get("route_family"),
        "cooldown_seconds": round(float(cooldown_seconds), 3),
        "cooldown_scope": cooldown_scope,
        "retry_after_seconds": retry_after,
        "error_tokens": sorted(error_tokens),
        "candidate": shaped_candidate,
    }
    if error_class is not None:
        detail["failure_class"] = error_class
    if error_status_code is not None:
        detail["error_status_code"] = error_status_code
    if error_type is not None:
        detail["error_type"] = error_type
    if error_code is not None:
        detail["error_code"] = str(error_code)
    if failure_phase is not None:
        detail["failure_phase"] = failure_phase
    if attempted_provider_call is not None:
        detail["attempted_provider_call"] = attempted_provider_call
    if isinstance(audit_events, list):
        detail["aawm_alias_routing_audit_events"] = audit_events
    if isinstance(attempts, list):
        detail["attempts"] = attempts
    if isinstance(skipped_candidates, list):
        detail["skipped_candidates"] = skipped_candidates
    return detail


def _raise_codex_auto_agent_redispatch_required(
    *,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    cooldown_seconds: float,
    error_tokens: set[str],
    alias_model: str = _CODEX_AUTO_AGENT_MODEL_ALIAS,
    error_class: Optional[str] = None,
    cooldown_scope: Optional[str] = None,
    error_status_code: Optional[Any] = None,
    error_type: Optional[str] = None,
    error_code: Optional[Any] = None,
    retry_after_seconds: Optional[Any] = None,
    failure_phase: Optional[str] = None,
    attempted_provider_call: Optional[bool] = None,
    audit_events: Optional[list[dict[str, Any]]] = None,
    attempts: Optional[list[dict[str, Any]]] = None,
    skipped_candidates: Optional[list[dict[str, Any]]] = None,
) -> None:
    detail = _build_auto_agent_redispatch_http_exception_detail(
        alias_family="codex_auto_agent",
        alias_model=alias_model,
        candidate=candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        error_tokens=error_tokens,
        error_class=error_class,
        cooldown_scope=cooldown_scope,
        error_status_code=error_status_code,
        error_type=error_type,
        error_code=error_code,
        retry_after_seconds=retry_after_seconds,
        failure_phase=failure_phase,
        attempted_provider_call=attempted_provider_call,
        audit_events=audit_events,
        attempts=attempts,
        skipped_candidates=skipped_candidates,
        code="aawm_codex_auto_agent_redispatch_required",
        message=(
            "Codex auto-agent alias target hit retryable provider exhaustion "
            "for an in-flight session. Do not continue this child agent. "
            f"Redispatch a fresh subagent using model {alias_model} "
            "so the auto selector can choose the next available candidate."
        ),
    )
    raise HTTPException(
        status_code=429,
        detail=detail,
        headers={"Retry-After": str(detail["retry_after_seconds"])},
    )


async def _get_codex_auto_agent_active_cooldown_state(
    cooldown_key: str,
) -> tuple[float, str]:
    async with _codex_auto_agent_lock:
        now = time.monotonic()
        until = _codex_auto_agent_cooldown_until_monotonic_by_key.get(cooldown_key, 0.0)
        if until > now:
            return max(0.0, until - now), "memory"
        _codex_auto_agent_cooldown_until_monotonic_by_key.pop(cooldown_key, None)
    # RR-054 #30: negative-cache durable misses so healthy keys do not Redis-hit every call.
    async with _codex_auto_agent_lock:
        neg_until = _codex_auto_agent_cooldown_negative_until_monotonic_by_key.get(cooldown_key, 0.0)
        if neg_until > time.monotonic():
            return 0.0, "negative_cache"
    dual_cache = _get_aawm_alias_routing_dual_cache()
    if dual_cache is None:
        return 0.0, "local_fallback"
    durable_payload = await _read_aawm_alias_routing_durable_payload(
        alias_family="codex",
        state_kind="cooldown",
        state_key=cooldown_key,
    )
    if durable_payload is None:
        async with _codex_auto_agent_lock:
            _codex_auto_agent_cooldown_negative_until_monotonic_by_key[cooldown_key] = (
                time.monotonic() + _AAWM_COOLDOWN_NEGATIVE_CACHE_TTL_SECONDS
            )
            _bound_aawm_alias_routing_memory_map(_codex_auto_agent_cooldown_negative_until_monotonic_by_key)
        return 0.0, "local_fallback"
    expires_at_epoch = _parse_aawm_alias_routing_durable_expiry(durable_payload)
    if expires_at_epoch is None:
        async with _codex_auto_agent_lock:
            _codex_auto_agent_cooldown_negative_until_monotonic_by_key[cooldown_key] = (
                time.monotonic() + _AAWM_COOLDOWN_NEGATIVE_CACHE_TTL_SECONDS
            )
            _bound_aawm_alias_routing_memory_map(_codex_auto_agent_cooldown_negative_until_monotonic_by_key)
        return 0.0, "local_fallback"
    async with _codex_auto_agent_lock:
        _codex_auto_agent_cooldown_negative_until_monotonic_by_key.pop(cooldown_key, None)
        _hydrate_aawm_alias_routing_cooldown_memory(
            memory_map=_codex_auto_agent_cooldown_until_monotonic_by_key,
            cooldown_key=cooldown_key,
            expires_at_epoch=expires_at_epoch,
        )
        until = _codex_auto_agent_cooldown_until_monotonic_by_key.get(cooldown_key, 0.0)
        return max(0.0, until - time.monotonic()), "durable_cache"


async def _get_codex_auto_agent_active_cooldown_seconds(
    cooldown_key: str,
) -> float:
    seconds, _ = await _get_codex_auto_agent_active_cooldown_state(cooldown_key)
    return seconds


async def _set_codex_auto_agent_cooldown(
    cooldown_key: str,
    cooldown_seconds: float,
) -> None:
    ttl_seconds = max(0.0, float(cooldown_seconds))
    async with _codex_auto_agent_lock:
        until = time.monotonic() + ttl_seconds
        current_until = _codex_auto_agent_cooldown_until_monotonic_by_key.get(cooldown_key, 0.0)
        if until > current_until:
            _codex_auto_agent_cooldown_until_monotonic_by_key[cooldown_key] = until
            _codex_auto_agent_cooldown_negative_until_monotonic_by_key.pop(cooldown_key, None)
            _bound_aawm_alias_routing_memory_map(_codex_auto_agent_cooldown_until_monotonic_by_key)
    if ttl_seconds <= 0:
        return
    await _write_aawm_alias_routing_durable_payload(
        alias_family="codex",
        state_kind="cooldown",
        state_key=cooldown_key,
        payload={"cooldown_key": cooldown_key},
        ttl_seconds=ttl_seconds,
    )


async def _get_codex_auto_agent_session_affinity(
    session_key: Optional[str],
) -> Optional[dict[str, Any]]:
    if session_key is None:
        return None
    async with _codex_auto_agent_lock:
        affinity = _codex_auto_agent_session_affinity_by_key.get(session_key)
        if isinstance(affinity, dict):
            expires_at = affinity.get("expires_at_monotonic", 0.0)
            if isinstance(expires_at, (int, float)) and expires_at > time.monotonic():
                hydrated = dict(affinity)
                hydrated["affinity_state_source"] = affinity.get("affinity_state_source", "memory")
                return hydrated
            _codex_auto_agent_session_affinity_by_key.pop(session_key, None)
    dual_cache = _get_aawm_alias_routing_dual_cache()
    if dual_cache is None:
        return None
    durable_payload = await _read_aawm_alias_routing_durable_payload(
        alias_family="codex",
        state_kind="affinity",
        state_key=session_key,
    )
    if durable_payload is None:
        return None
    expires_at_epoch = _parse_aawm_alias_routing_durable_expiry(durable_payload)
    if expires_at_epoch is None:
        return None
    async with _codex_auto_agent_lock:
        affinity = _hydrate_aawm_alias_routing_affinity_memory(
            memory_map=_codex_auto_agent_session_affinity_by_key,
            session_key=session_key,
            payload=durable_payload,
            expires_at_epoch=expires_at_epoch,
        )
        if not affinity:
            return None
        affinity["affinity_state_source"] = "durable_cache"
        return dict(affinity)


async def _set_codex_auto_agent_session_affinity(
    session_key: Optional[str],
    candidate: dict[str, Any],
) -> None:
    if session_key is None:
        return
    async with _codex_auto_agent_lock:
        _codex_auto_agent_session_affinity_by_key[session_key] = {
            "provider": candidate["provider"],
            "model": candidate["model"],
            "route_family": candidate["route_family"],
            "last_resort": bool(candidate.get("last_resort")),
            "expires_at_monotonic": (time.monotonic() + _CODEX_AUTO_AGENT_SESSION_AFFINITY_TTL_SECONDS),
            "affinity_state_source": "memory",
        }
        _bound_aawm_alias_routing_memory_map(_codex_auto_agent_session_affinity_by_key)
    await _write_aawm_alias_routing_durable_payload(
        alias_family="codex",
        state_kind="affinity",
        state_key=session_key,
        payload={
            "provider": candidate["provider"],
            "model": candidate["model"],
            "route_family": candidate["route_family"],
            "last_resort": bool(candidate.get("last_resort")),
        },
        ttl_seconds=_CODEX_AUTO_AGENT_SESSION_AFFINITY_TTL_SECONDS,
    )


def _find_codex_auto_agent_candidate(
    provider: Any,
    model: Any,
    *,
    alias_model: str = _CODEX_AUTO_AGENT_MODEL_ALIAS,
    client_product_label: Optional[str] = None,
) -> Optional[dict[str, Any]]:
    for candidate in _get_codex_auto_agent_candidates_for_alias(
        alias_model,
        client_product_label=client_product_label,
    ):
        if candidate["provider"] == provider and candidate["model"] == model:
            return dict(candidate)
    return None


def _is_auto_agent_candidate_state_available(state: dict[str, Any]) -> bool:
    return state["cooldown_seconds"] <= 0 and state.get("skip_reason") is None


def _build_auto_agent_skipped_candidates_from_states(
    states: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    skipped: list[dict[str, Any]] = []
    for state in states:
        if _is_auto_agent_candidate_state_available(state):
            continue
        shaped = _codex_auto_agent_candidate_public_shape(
            state["candidate"],
            lane_key=state["lane_key"],
            cooldown_seconds=(state["cooldown_seconds"] if state["cooldown_seconds"] > 0 else None),
            reason=state.get("skip_reason") or "cooldown",
        )
        for field in (
            "cooldown_state_source",
            "cooldown_scope",
            "failure_phase",
            "attempted_provider_call",
        ):
            if field in state:
                shaped[field] = state[field]
        skipped.append(shaped)
    return skipped


async def _apply_codex_auto_agent_forced_candidate_cooldown(
    *,
    cooldown_key: str,
    cooldown_seconds: float,
) -> None:
    await _set_codex_auto_agent_cooldown(cooldown_key, cooldown_seconds)


async def _apply_anthropic_auto_agent_forced_candidate_cooldown(
    *,
    cooldown_key: str,
    cooldown_seconds: float,
) -> None:
    await _set_anthropic_auto_agent_cooldown(cooldown_key, cooldown_seconds)


def _apply_codex_auto_agent_request_local_candidate_state(
    request: Request,
    *,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    cooldown_seconds: float,
    cooldown_state_source: Optional[str],
    skip_reason: Optional[str],
) -> tuple[float, Optional[str], Optional[str]]:
    request_local_cooldown_key = _get_codex_auto_agent_request_local_cooldown_key(
        candidate=candidate,
        lane_key=lane_key,
    )
    request_local_cooldown_seconds = _get_codex_auto_agent_request_local_cooldown_seconds(
        request,
        cooldown_key=request_local_cooldown_key,
    )
    if request_local_cooldown_seconds > cooldown_seconds:
        cooldown_seconds = request_local_cooldown_seconds
        cooldown_state_source = "request_local"
    if request_local_cooldown_key in _get_codex_auto_agent_request_local_excluded_keys(request):
        if request_local_cooldown_seconds <= 0:
            cooldown_seconds = max(cooldown_seconds, 0.001)
        cooldown_state_source = "request_local"
        skip_reason = "request_local_transient_failure"
    return cooldown_seconds, cooldown_state_source, skip_reason


async def _apply_codex_auto_agent_adapter_local_candidate_cooldown(
    *,
    candidate: dict[str, Any],
    cooldown_seconds: float,
    cooldown_state_source: Optional[str],
    skip_reason: Optional[str],
) -> tuple[float, Optional[str], Optional[str]]:
    """Merge process-local adapter cooldown evidence into alias selection state."""
    provider = candidate.get("provider")
    model = candidate.get("model")
    adapter_seconds = 0.0
    if provider == _CODEX_AUTO_AGENT_OPENROUTER_PROVIDER:
        adapter_seconds = await _get_openrouter_adapter_active_cooldown_seconds(model)
    elif provider == _CODEX_AUTO_AGENT_GOOGLE_PROVIDER:
        lane_key = await _resolve_codex_auto_agent_google_lane_key()
        async with _google_adapter_rate_limit_lock:
            now = time.monotonic()
            adapter_seconds = max(
                0.0,
                _google_adapter_rate_limit_until_monotonic_by_key.get(lane_key, 0.0) - now,
            )
    if adapter_seconds <= 0:
        return cooldown_seconds, cooldown_state_source, skip_reason
    if adapter_seconds > cooldown_seconds:
        cooldown_seconds = adapter_seconds
        cooldown_state_source = "adapter_local"
    if cooldown_seconds > 0 and skip_reason is None:
        skip_reason = "adapter_cooldown"
    return cooldown_seconds, cooldown_state_source, skip_reason


async def _apply_kimi_code_managed_account_lane_cooldown(
    *,
    candidate: dict[str, Any],
    cooldown_seconds: float,
    cooldown_state_source: Optional[str],
    skip_reason: Optional[str],
    get_active_cooldown_state: Callable[[str], Awaitable[tuple[float, str]]],
) -> tuple[float, Optional[str], Optional[str], Optional[str]]:
    """Apply one Kimi managed-account lane without conflating candidate gates."""

    if not _is_kimi_code_auto_agent_candidate(candidate):
        return cooldown_seconds, cooldown_state_source, skip_reason, None
    managed_seconds, managed_source = await get_active_cooldown_state(_get_kimi_code_managed_account_cooldown_key())
    if managed_seconds <= 0:
        return cooldown_seconds, cooldown_state_source, skip_reason, None
    if managed_seconds >= cooldown_seconds:
        cooldown_seconds = managed_seconds
        cooldown_state_source = f"kimi_managed_account:{managed_source}"
    return cooldown_seconds, cooldown_state_source, skip_reason, "managed_account"


async def _build_codex_auto_agent_candidate_state(  # noqa: PLR0915
    request: Request,
    *,
    candidate_template: dict[str, Any],
    alias_model: str = _CODEX_AUTO_AGENT_MODEL_ALIAS,
    openai_lane_key: Optional[str] = None,
    google_lane_key: Optional[str] = None,
    antigravity_lane_state: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    candidate = dict(candidate_template)
    if openai_lane_key is None:
        openai_lane_key = _resolve_codex_auto_agent_openai_cooldown_lane_key(request)
    forced_cooldown_seconds: Optional[float] = None
    skip_reason: Optional[str] = None
    cooldown_state_source_override: Optional[str] = None
    failure_phase: Optional[str] = None
    attempted_provider_call: Optional[bool] = None
    if candidate["provider"] == _CODEX_AUTO_AGENT_GOOGLE_PROVIDER:
        if google_lane_key is None:
            google_lane_key = await _resolve_codex_auto_agent_google_lane_key()
        lane_key = google_lane_key
        if lane_key == _CODEX_AUTO_AGENT_GOOGLE_AUTH_DEGRADED_LANE_KEY:
            forced_cooldown_seconds = _CODEX_AUTO_AGENT_AUTH_DEGRADED_COOLDOWN_SECONDS
            skip_reason = "auth_degraded"
            cooldown_state_source_override = "auth_degraded"
            failure_phase = "auth"
            attempted_provider_call = False
    elif candidate["provider"] == _CODEX_AUTO_AGENT_ANTIGRAVITY_PROVIDER:
        if antigravity_lane_state is None:
            antigravity_lane_state = await _resolve_codex_auto_agent_antigravity_lane_state()
        lane_key = str(antigravity_lane_state["lane_key"])
        forced_cooldown_seconds = _auto_agent_alias_float(antigravity_lane_state.get("forced_cooldown_seconds"))
        skip_reason = cast(Optional[str], antigravity_lane_state.get("skip_reason"))
        cooldown_state_source_override = cast(Optional[str], antigravity_lane_state.get("cooldown_state_source"))
        failure_phase = cast(Optional[str], antigravity_lane_state.get("failure_phase"))
        attempted_provider_call = cast(Optional[bool], antigravity_lane_state.get("attempted_provider_call"))
    elif candidate["provider"] == _CODEX_AUTO_AGENT_OPENROUTER_PROVIDER:
        lane_key = _CODEX_AUTO_AGENT_OPENROUTER_LANE_KEY
    elif candidate["provider"] == _CODEX_AUTO_AGENT_XAI_PROVIDER:
        lane_key = _resolve_codex_auto_agent_xai_lane_key(candidate)
    elif candidate["provider"] == _CODEX_AUTO_AGENT_KIMI_CODE_PROVIDER:
        lane_key = _CODEX_AUTO_AGENT_KIMI_CODE_LANE_KEY
    elif candidate["provider"] == _CODEX_AUTO_AGENT_ALIBABA_TOKEN_PLAN_PROVIDER:
        lane_key = _CODEX_AUTO_AGENT_ALIBABA_TOKEN_PLAN_LANE_KEY
    elif candidate["provider"] == _CODEX_AUTO_AGENT_OPENCODE_PROVIDER:
        lane_key = _CODEX_AUTO_AGENT_OPENCODE_LANE_KEY
    else:
        lane_key = openai_lane_key
    cooldown_key = _codex_auto_agent_candidate_key(candidate, lane_key)
    (
        cooldown_seconds,
        initial_cooldown_state_source,
    ) = await _get_codex_auto_agent_active_cooldown_state(cooldown_key)
    cooldown_state_source: Optional[str] = initial_cooldown_state_source
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
    ) = await _apply_codex_auto_agent_grok_account_lane_cooldown(
        candidate=candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
        get_active_cooldown_state=_get_codex_auto_agent_active_cooldown_state,
    )
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
        managed_account_cooldown_scope,
    ) = await _apply_kimi_code_managed_account_lane_cooldown(
        candidate=candidate,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
        get_active_cooldown_state=_get_codex_auto_agent_active_cooldown_state,
    )
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
    ) = _apply_codex_auto_agent_request_local_candidate_state(
        request,
        candidate=candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
    )
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
    ) = await _apply_codex_auto_agent_adapter_local_candidate_cooldown(
        candidate=candidate,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
    )
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
    ) = await _apply_openrouter_durable_quota_candidate_cooldown(
        candidate=candidate,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
    )
    if forced_cooldown_seconds is not None and forced_cooldown_seconds > cooldown_seconds:
        await _apply_codex_auto_agent_forced_candidate_cooldown(
            cooldown_key=cooldown_key,
            cooldown_seconds=forced_cooldown_seconds,
        )
        cooldown_seconds = forced_cooldown_seconds
        cooldown_state_source = cooldown_state_source_override or "forced_candidate_cooldown"
    state = {
        "candidate": candidate,
        "lane_key": lane_key,
        "cooldown_key": cooldown_key,
        "cooldown_seconds": cooldown_seconds,
        "cooldown_state_source": cooldown_state_source,
    }
    if skip_reason is not None:
        state["skip_reason"] = skip_reason
    if failure_phase is not None:
        state["failure_phase"] = failure_phase
    if attempted_provider_call is not None:
        state["attempted_provider_call"] = attempted_provider_call
    if managed_account_cooldown_scope is not None:
        state["cooldown_scope"] = managed_account_cooldown_scope
    return state


async def _get_anthropic_auto_agent_candidate_cooldown_state(
    *,
    provider: str,
    cooldown_key: str,
) -> tuple[float, str]:
    """OpenAI/Codex candidates merge Anthropic + Codex cooldown; others use Anthropic-only."""
    if provider in {
        _CODEX_AUTO_AGENT_NATIVE_PROVIDER,
        _CODEX_AUTO_AGENT_KIMI_CODE_PROVIDER,
        _CODEX_AUTO_AGENT_ALIBABA_TOKEN_PLAN_PROVIDER,
    }:
        return await _get_anthropic_auto_agent_merged_codex_openai_cooldown_state(cooldown_key)
    return await _get_anthropic_auto_agent_active_cooldown_state(cooldown_key)


async def _build_anthropic_auto_agent_candidate_state(  # noqa: PLR0915
    request: Request,
    *,
    candidate_template: dict[str, Any],
    alias_model: str = _ANTHROPIC_AUTO_AGENT_MODEL_ALIAS,
    openai_lane_key: Optional[str] = None,
    anthropic_lane_key: Optional[str] = None,
    google_lane_key: Optional[str] = None,
    antigravity_lane_state: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    candidate = dict(candidate_template)
    if openai_lane_key is None:
        openai_lane_key = _resolve_codex_auto_agent_openai_cooldown_lane_key(request)
    if anthropic_lane_key is None:
        anthropic_lane_key = _resolve_anthropic_auto_agent_native_cooldown_lane_key(request)
    forced_cooldown_seconds: Optional[float] = None
    skip_reason: Optional[str] = None
    cooldown_state_source_override: Optional[str] = None
    failure_phase: Optional[str] = None
    attempted_provider_call: Optional[bool] = None
    if candidate["provider"] == _CODEX_AUTO_AGENT_GOOGLE_PROVIDER:
        if google_lane_key is None:
            google_lane_key = await _resolve_codex_auto_agent_google_lane_key()
        lane_key = google_lane_key
        if lane_key == _CODEX_AUTO_AGENT_GOOGLE_AUTH_DEGRADED_LANE_KEY:
            forced_cooldown_seconds = _CODEX_AUTO_AGENT_AUTH_DEGRADED_COOLDOWN_SECONDS
            skip_reason = "auth_degraded"
            cooldown_state_source_override = "auth_degraded"
            failure_phase = "auth"
            attempted_provider_call = False
    elif candidate["provider"] == _CODEX_AUTO_AGENT_ANTIGRAVITY_PROVIDER:
        if antigravity_lane_state is None:
            antigravity_lane_state = await _resolve_codex_auto_agent_antigravity_lane_state()
        lane_key = str(antigravity_lane_state["lane_key"])
        forced_cooldown_seconds = _auto_agent_alias_float(antigravity_lane_state.get("forced_cooldown_seconds"))
        skip_reason = cast(Optional[str], antigravity_lane_state.get("skip_reason"))
        cooldown_state_source_override = cast(Optional[str], antigravity_lane_state.get("cooldown_state_source"))
        failure_phase = cast(Optional[str], antigravity_lane_state.get("failure_phase"))
        attempted_provider_call = cast(Optional[bool], antigravity_lane_state.get("attempted_provider_call"))
    elif candidate["provider"] == _CODEX_AUTO_AGENT_OPENROUTER_PROVIDER:
        lane_key = _CODEX_AUTO_AGENT_OPENROUTER_LANE_KEY
    elif candidate["provider"] == _CODEX_AUTO_AGENT_XAI_PROVIDER:
        lane_key = _resolve_codex_auto_agent_xai_lane_key(candidate)
    elif candidate["provider"] == _CODEX_AUTO_AGENT_KIMI_CODE_PROVIDER:
        lane_key = _CODEX_AUTO_AGENT_KIMI_CODE_LANE_KEY
    elif candidate["provider"] == _CODEX_AUTO_AGENT_ALIBABA_TOKEN_PLAN_PROVIDER:
        lane_key = _CODEX_AUTO_AGENT_ALIBABA_TOKEN_PLAN_LANE_KEY
    elif candidate["provider"] == _CODEX_AUTO_AGENT_OPENCODE_PROVIDER:
        lane_key = _CODEX_AUTO_AGENT_OPENCODE_LANE_KEY
    elif candidate["provider"] == _ANTHROPIC_AUTO_AGENT_NATIVE_PROVIDER:
        lane_key = anthropic_lane_key
    else:
        lane_key = openai_lane_key
    cooldown_key = _codex_auto_agent_candidate_key(candidate, lane_key)
    (
        cooldown_seconds,
        initial_cooldown_state_source,
    ) = await _get_anthropic_auto_agent_candidate_cooldown_state(
        provider=candidate["provider"],
        cooldown_key=cooldown_key,
    )
    cooldown_state_source: Optional[str] = initial_cooldown_state_source
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
    ) = await _apply_codex_auto_agent_grok_account_lane_cooldown(
        candidate=candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
        get_active_cooldown_state=_get_anthropic_auto_agent_active_cooldown_state,
    )
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
        managed_account_cooldown_scope,
    ) = await _apply_kimi_code_managed_account_lane_cooldown(
        candidate=candidate,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
        get_active_cooldown_state=lambda cooldown_key: (
            _get_anthropic_auto_agent_candidate_cooldown_state(
                provider=_CODEX_AUTO_AGENT_KIMI_CODE_PROVIDER,
                cooldown_key=cooldown_key,
            )
        ),
    )
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
    ) = _apply_codex_auto_agent_request_local_candidate_state(
        request,
        candidate=candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
    )
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
    ) = await _apply_codex_auto_agent_adapter_local_candidate_cooldown(
        candidate=candidate,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
    )
    (
        cooldown_seconds,
        cooldown_state_source,
        skip_reason,
    ) = await _apply_openrouter_durable_quota_candidate_cooldown(
        candidate=candidate,
        cooldown_seconds=cooldown_seconds,
        cooldown_state_source=cooldown_state_source,
        skip_reason=skip_reason,
    )
    if forced_cooldown_seconds is not None and forced_cooldown_seconds > cooldown_seconds:
        await _apply_anthropic_auto_agent_forced_candidate_cooldown(
            cooldown_key=cooldown_key,
            cooldown_seconds=forced_cooldown_seconds,
        )
        cooldown_seconds = forced_cooldown_seconds
        cooldown_state_source = cooldown_state_source_override or "forced_candidate_cooldown"
    state = {
        "candidate": candidate,
        "lane_key": lane_key,
        "cooldown_key": cooldown_key,
        "cooldown_seconds": cooldown_seconds,
        "cooldown_state_source": cooldown_state_source,
    }
    if skip_reason is not None:
        state["skip_reason"] = skip_reason
    if failure_phase is not None:
        state["failure_phase"] = failure_phase
    if attempted_provider_call is not None:
        state["attempted_provider_call"] = attempted_provider_call
    if managed_account_cooldown_scope is not None:
        state["cooldown_scope"] = managed_account_cooldown_scope
    return state


async def _build_codex_auto_agent_candidate_states(
    request: Request,
    *,
    alias_model: str = _CODEX_AUTO_AGENT_MODEL_ALIAS,
    client_product_label: Optional[str] = None,
) -> list[dict[str, Any]]:
    openai_lane_key = _resolve_codex_auto_agent_openai_cooldown_lane_key(request)
    google_lane_key: Optional[str] = None
    antigravity_lane_state: Optional[dict[str, Any]] = None
    states: list[dict[str, Any]] = []
    for candidate_template in _get_codex_auto_agent_candidates_for_alias(
        alias_model,
        client_product_label=client_product_label,
    ):
        if candidate_template["provider"] == _CODEX_AUTO_AGENT_GOOGLE_PROVIDER and google_lane_key is None:
            google_lane_key = await _resolve_codex_auto_agent_google_lane_key()
        if candidate_template["provider"] == _CODEX_AUTO_AGENT_ANTIGRAVITY_PROVIDER and antigravity_lane_state is None:
            antigravity_lane_state = await _resolve_codex_auto_agent_antigravity_lane_state()
        states.append(
            await _build_codex_auto_agent_candidate_state(
                request,
                candidate_template=candidate_template,
                alias_model=alias_model,
                openai_lane_key=openai_lane_key,
                google_lane_key=google_lane_key,
                antigravity_lane_state=antigravity_lane_state,
            )
        )
    return states


def _attach_aawm_alias_routing_state_sources(
    selection: dict[str, Any],
    *,
    affinity: Optional[dict[str, Any]] = None,
    selected_state: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    enriched = dict(selection)
    if affinity is not None:
        enriched["affinity_state_source"] = affinity.get("affinity_state_source", "local_fallback")
    if selected_state is not None:
        enriched["cooldown_state_source"] = selected_state.get("cooldown_state_source", "local_fallback")
    return enriched


async def _select_codex_auto_agent_candidate(
    *,
    request: Request,
    request_body: dict[str, Any],
) -> dict[str, Any]:
    alias_model = _normalize_codex_auto_agent_alias_model(request_body.get("model")) or _CODEX_AUTO_AGENT_MODEL_ALIAS
    client_product_label = _extract_auto_agent_alias_client_product_label(request, request_body)
    session_key = _resolve_codex_auto_agent_session_key(
        request,
        request_body,
        alias_model=alias_model,
    )
    has_continuation_state = _codex_auto_agent_request_has_continuation_state(request_body)

    affinity = await _get_codex_auto_agent_session_affinity(session_key)
    if affinity is not None and not has_continuation_state:
        affinity = None
    if affinity is not None and has_continuation_state:
        affinity_candidate = _find_codex_auto_agent_candidate(
            affinity.get("provider"),
            affinity.get("model"),
            alias_model=alias_model,
            client_product_label=client_product_label,
        )
        if affinity_candidate is not None:
            affinity_state = await _build_codex_auto_agent_candidate_state(
                request,
                candidate_template=affinity_candidate,
                alias_model=alias_model,
            )
            if _is_auto_agent_candidate_state_available(affinity_state):
                return _attach_aawm_alias_routing_state_sources(
                    {
                        **affinity_state,
                        "alias_model": alias_model,
                        "session_key": session_key,
                        "selection_reason": "session_affinity",
                        "skipped": [],
                        "in_flight_session": has_continuation_state,
                    },
                    affinity=affinity,
                    selected_state=affinity_state,
                )
            if affinity_state["cooldown_seconds"] > 0:
                _raise_codex_auto_agent_in_flight_cooldown(
                    candidate=affinity_candidate,
                    lane_key=affinity_state.get("lane_key"),
                    cooldown_seconds=affinity_state["cooldown_seconds"],
                )

    states = await _build_codex_auto_agent_candidate_states(
        request,
        alias_model=alias_model,
        client_product_label=client_product_label,
    )
    skipped = _build_auto_agent_skipped_candidates_from_states(states)

    if affinity is not None:
        affinity_candidate = _find_codex_auto_agent_candidate(
            affinity.get("provider"),
            affinity.get("model"),
            alias_model=alias_model,
            client_product_label=client_product_label,
        )
        if affinity_candidate is not None:
            matched_affinity_state: Optional[dict[str, Any]] = None
            for state in states:
                if (
                    state["candidate"]["provider"] == affinity_candidate["provider"]
                    and state["candidate"]["model"] == affinity_candidate["model"]
                ):
                    matched_affinity_state = state
                    break
            if matched_affinity_state is not None:
                if not _is_auto_agent_candidate_state_available(matched_affinity_state):
                    if has_continuation_state:
                        if matched_affinity_state["cooldown_seconds"] > 0:
                            _raise_codex_auto_agent_in_flight_cooldown(
                                candidate=affinity_candidate,
                                lane_key=matched_affinity_state.get("lane_key"),
                                cooldown_seconds=matched_affinity_state["cooldown_seconds"],
                            )
                    skipped.append(
                        _codex_auto_agent_candidate_public_shape(
                            affinity_candidate,
                            lane_key=matched_affinity_state.get("lane_key"),
                            cooldown_seconds=(
                                matched_affinity_state["cooldown_seconds"]
                                if matched_affinity_state["cooldown_seconds"] > 0
                                else None
                            ),
                            reason=matched_affinity_state.get("skip_reason") or "session_affinity_cooldown",
                        )
                    )
                else:
                    return _attach_aawm_alias_routing_state_sources(
                        {
                            **matched_affinity_state,
                            "alias_model": alias_model,
                            "session_key": session_key,
                            "selection_reason": "session_affinity",
                            "skipped": skipped,
                            "in_flight_session": has_continuation_state,
                        },
                        affinity=affinity,
                        selected_state=matched_affinity_state,
                    )
            preferred_available = any(
                not state["candidate"].get("last_resort") and _is_auto_agent_candidate_state_available(state)
                for state in states
            )
            if (
                matched_affinity_state is not None
                and _is_auto_agent_candidate_state_available(matched_affinity_state)
                and (not affinity_candidate.get("last_resort") or not preferred_available)
            ):
                return _attach_aawm_alias_routing_state_sources(
                    {
                        **matched_affinity_state,
                        "alias_model": alias_model,
                        "session_key": session_key,
                        "selection_reason": "session_affinity",
                        "skipped": skipped,
                    },
                    affinity=affinity,
                    selected_state=matched_affinity_state,
                )

    for state in states:
        if state["candidate"].get("last_resort") or not _is_auto_agent_candidate_state_available(state):
            continue
        return _attach_aawm_alias_routing_state_sources(
            {
                **state,
                "alias_model": alias_model,
                "session_key": session_key,
                "selection_reason": "first_available",
                "skipped": skipped,
            },
            selected_state=state,
        )

    for state in states:
        if not state["candidate"].get("last_resort") or not _is_auto_agent_candidate_state_available(state):
            continue
        return _attach_aawm_alias_routing_state_sources(
            {
                **state,
                "alias_model": alias_model,
                "session_key": session_key,
                "selection_reason": "last_resort",
                "skipped": skipped,
            },
            selected_state=state,
        )

    raise HTTPException(
        status_code=429,
        detail={
            "error": {
                "message": ("All Codex auto-agent alias candidates are currently cooled down."),
                "type": "rate_limit_error",
                "code": "aawm_codex_auto_agent_all_candidates_cooling_down",
            },
            "candidates": skipped,
        },
    )


def _codex_auto_agent_error_text(exc: Any) -> str:
    detail = _extract_google_adapter_exception_detail(exc)
    if isinstance(detail, bytes):
        detail_text = detail.decode("utf-8", errors="ignore")
    else:
        detail_text = str(detail)
    return " ".join(
        str(part)
        for part in (
            getattr(exc, "message", None),
            getattr(exc, "code", None),
            detail_text,
            str(exc),
        )
        if part is not None
    )


def _add_codex_auto_agent_text_error_tokens(
    tokens: set[str],
    text_lower: str,
) -> None:
    if "grok build usage balance exhausted" in text_lower:
        tokens.add(_CODEX_AUTO_AGENT_GROK_BUILD_USAGE_BALANCE_EXHAUSTED_TOKEN)
    if "personal-team-blocked:spending-limit" in text_lower:
        tokens.add(_CODEX_AUTO_AGENT_GROK_PERSONAL_TEAM_SPENDING_LIMIT_TOKEN)
    if (
        "usage_limit_reached" in text_lower
        or "usage limit" in text_lower
        or "weekly limit" in text_lower
        or "quota exceeded" in text_lower
        or "quota exhausted" in text_lower
        or "quota limit" in text_lower
    ):
        tokens.add("usage_limit_reached")
    if "resource_exhausted" in text_lower or "resource exhausted" in text_lower:
        tokens.add("RESOURCE_EXHAUSTED")
    if "model_capacity_exhausted" in text_lower or "model capacity exhausted" in text_lower:
        tokens.add("MODEL_CAPACITY_EXHAUSTED")
    if "currently experiencing high demand" in text_lower or "experiencing high demand" in text_lower:
        tokens.add("HIGH_DEMAND")
    if "selected model is at capacity" in text_lower or (
        "model is at capacity" in text_lower and "try a different model" in text_lower
    ):
        tokens.add("MODEL_AT_CAPACITY")
    if "model is overloaded" in text_lower or "overloaded_error" in text_lower:
        tokens.add("MODEL_OVERLOADED")
    if "busy upstream" in text_lower or ("upstream" in text_lower and "busy" in text_lower):
        tokens.add("UPSTREAM_BUSY")
    if "rate_limit_exceeded" in text_lower or "rate limit" in text_lower:
        tokens.add("RATE_LIMIT_EXCEEDED")
    if "too many requests" in text_lower:
        tokens.add("429")
        tokens.add("RATE_LIMIT_EXCEEDED")
    if "aawm_codex_auto_agent_candidate_unavailable" in text_lower:
        tokens.add("aawm_codex_auto_agent_candidate_unavailable")
    if "not supported when using codex with a chatgpt account" in text_lower and (
        "model is not supported" in text_lower or " is not supported" in text_lower
    ):
        tokens.add("aawm_codex_auto_agent_candidate_unavailable")
    if "grok-4.5" in text_lower and any(
        marker in text_lower
        for marker in (
            "model not found",
            "model does not exist",
            "model is not available",
            "unknown model",
            "unsupported model",
        )
    ):
        tokens.add("aawm_codex_auto_agent_candidate_unavailable")
    if "aawm_auto_agent_failed_responses_payload" in text_lower:
        tokens.add("aawm_auto_agent_failed_responses_payload")
    if "aawm_auto_agent_malformed_tool_call_text" in text_lower:
        tokens.add("aawm_auto_agent_malformed_tool_call_text")
    if (
        "permission-denied" in text_lower
        and "content violates usage guidelines" in text_lower
        and "safety_check_type_cyber" in text_lower
    ):
        tokens.add("safety_policy_denied")
    if (
        "error from provider (deepseek)" in text_lower
        and "assistant message with 'tool_calls' must be followed by tool messages" in text_lower
    ) or "insufficient tool messages following tool_calls message" in text_lower:
        tokens.add("DEEPSEEK_TOOL_MESSAGE_MISMATCH")
    if "invalid message provided" in text_lower and "must have non-empty content or tool calls" in text_lower:
        tokens.add("OPENROUTER_INVALID_CHAT_MESSAGE")
    if "invalid tool call provided" in text_lower and "tool arguments must be a stringified json object" in text_lower:
        tokens.add("OPENROUTER_INVALID_TOOL_CALL_ARGUMENTS")


def _extract_codex_auto_agent_error_tokens(exc: Any) -> set[str]:
    tokens: set[str] = set()
    for parsed in _extract_google_adapter_error_payloads(exc):
        error_blocks: list[dict[str, Any]] = []
        if isinstance(parsed, dict):
            error = parsed.get("error")
            if isinstance(error, dict):
                error_blocks.append(error)
        elif isinstance(parsed, list):
            for item in parsed:
                if isinstance(item, dict) and isinstance(item.get("error"), dict):
                    error_blocks.append(item["error"])
        for error in error_blocks:
            for key in ("code", "status", "type"):
                value = error.get(key)
                if isinstance(value, str) and value:
                    tokens.add(value)
                elif isinstance(value, int):
                    tokens.add(str(value))
            details = error.get("details")
            if isinstance(details, list):
                for detail in details:
                    if not isinstance(detail, dict):
                        continue
                    reason = detail.get("reason")
                    if isinstance(reason, str) and reason:
                        tokens.add(reason)
            message = error.get("message")
            if isinstance(message, str) and message:
                lowered = message.lower()
                if "usage_limit_reached" in lowered:
                    tokens.add("usage_limit_reached")
                if "resource_exhausted" in lowered:
                    tokens.add("RESOURCE_EXHAUSTED")
                if "model_capacity_exhausted" in lowered:
                    tokens.add("MODEL_CAPACITY_EXHAUSTED")
    text_lower = _codex_auto_agent_error_text(exc).lower()
    _add_codex_auto_agent_text_error_tokens(tokens, text_lower)
    if _is_openrouter_adapter_provider_raw_error(exc):
        tokens.add("OPENROUTER_PROVIDER_RAW_ERROR")
    return tokens


def _is_codex_auto_agent_durable_cooldown_error_class(
    error_class: Optional[str],
) -> bool:
    return error_class in _CODEX_AUTO_AGENT_DURABLE_COOLDOWN_ERROR_CLASSES


def _is_codex_auto_agent_spark_candidate(candidate: Optional[dict[str, Any]]) -> bool:
    if not isinstance(candidate, dict):
        return False
    return str(candidate.get("model") or "") == _CODEX_AUTO_AGENT_SPARK_MODEL


def _is_codex_auto_agent_grok_4_5_candidate(
    candidate: Optional[dict[str, Any]],
) -> bool:
    if not isinstance(candidate, dict):
        return False
    if candidate.get("provider") != _CODEX_AUTO_AGENT_XAI_PROVIDER:
        return False
    model = str(candidate.get("model") or "")
    if model in {"oa_xai/grok-4.5", "grok-4.5", "xai/grok-4.5"}:
        return True
    route_family = str(candidate.get("route_family") or "")
    return route_family in {
        "codex_xai_oauth_responses_adapter",
        "codex_grok_native_responses_adapter",
        "anthropic_grok_native_responses_adapter",
    } and model.endswith("grok-4.5")


def _is_codex_auto_agent_native_grok_4_5_candidate(
    candidate: Optional[dict[str, Any]],
) -> bool:
    if not _is_codex_auto_agent_grok_4_5_candidate(candidate):
        return False
    route_family = str((candidate or {}).get("route_family") or "")
    return route_family in {
        "codex_grok_native_responses_adapter",
        "anthropic_grok_native_responses_adapter",
    }


def _is_codex_auto_agent_xai_candidate(
    candidate: Optional[dict[str, Any]],
) -> bool:
    if not isinstance(candidate, dict):
        return False
    return candidate.get("provider") == _CODEX_AUTO_AGENT_XAI_PROVIDER


_KIMI_CODE_SAFE_FAILURE_KINDS = frozenset(
    {
        "refresh_required_auth",
        "quota",
        "provider_capacity",
        "transient",
        "malformed",
        "unsupported_model",
        "unsupported_effort",
        "unsupported_capability",
        "unknown",
    }
)
_KIMI_CODE_SAFE_FAILURE_SCOPES = frozenset({"managed_account", "candidate", "telemetry", "none"})
_KIMI_CODE_SAFE_METADATA_GATES = frozenset({"none", "model_id", "think_effort", "capability"})
_KIMI_CODE_SAFE_RESET_REASONS = frozenset(
    {
        "refresh_required",
        "quota_exhausted",
        "provider_capacity",
        "transient_upstream_failure",
        "malformed_provider_response",
        "unsupported_model",
        "unsupported_effort",
        "unsupported_capability",
        "unclassified_failure",
    }
)
_KIMI_CODE_SAFE_UPSTREAM_IDS = frozenset({"k3", "kimi-for-coding", "kimi-for-coding-highspeed"})
_KIMI_CODE_MANAGED_ACCOUNT_COOLDOWN_MODEL = "__managed_account__"


def _is_kimi_code_auto_agent_candidate(candidate: Optional[dict[str, Any]]) -> bool:
    return isinstance(candidate, dict) and candidate.get("provider") == _CODEX_AUTO_AGENT_KIMI_CODE_PROVIDER


def _get_kimi_code_managed_account_cooldown_key() -> str:
    return _codex_auto_agent_candidate_key(
        {
            "provider": _CODEX_AUTO_AGENT_KIMI_CODE_PROVIDER,
            "model": _KIMI_CODE_MANAGED_ACCOUNT_COOLDOWN_MODEL,
        },
        _CODEX_AUTO_AGENT_KIMI_CODE_LANE_KEY,
    )


def _get_safe_kimi_code_probe_failure_metadata(
    exc: Any,
    *,
    candidate: Optional[dict[str, Any]],
) -> Optional[dict[str, Any]]:
    """Return only adapter-classifier allowlisted Kimi probe metadata."""

    if not _is_kimi_code_auto_agent_candidate(candidate):
        return None
    raw_metadata = getattr(exc, "kimi_code_probe_failure_metadata", None)
    if not isinstance(raw_metadata, dict):
        return None
    kind = raw_metadata.get("kind")
    scope = raw_metadata.get("scope")
    upstream_id = raw_metadata.get("upstream_id")
    metadata_gate = raw_metadata.get("metadata_gate")
    reset_reason = raw_metadata.get("reset_reason")
    status_code = raw_metadata.get("status_code")
    trace_id = raw_metadata.get("trace_id")
    if (
        kind not in _KIMI_CODE_SAFE_FAILURE_KINDS
        or scope not in _KIMI_CODE_SAFE_FAILURE_SCOPES
        or upstream_id not in _KIMI_CODE_SAFE_UPSTREAM_IDS
        or metadata_gate not in _KIMI_CODE_SAFE_METADATA_GATES
        or reset_reason not in _KIMI_CODE_SAFE_RESET_REASONS
    ):
        return None
    if status_code is not None and (
        not isinstance(status_code, int) or isinstance(status_code, bool) or status_code < 100 or status_code > 599
    ):
        return None
    if trace_id is not None and (
        not isinstance(trace_id, str)
        or len(trace_id) > 256
        or not trace_id
        or any(not (character.isalnum() or character in "._-") for character in trace_id)
    ):
        return None
    return {
        "kind": kind,
        "scope": scope,
        "upstream_id": upstream_id,
        "metadata_gate": metadata_gate,
        "status_code": status_code,
        "trace_id": trace_id,
        "reset_reason": reset_reason,
    }


def _classify_kimi_code_auto_agent_probe_failure(
    metadata: Optional[dict[str, Any]],
) -> Optional[str]:
    if metadata is None:
        return None
    scope = metadata["scope"]
    if scope == "managed_account":
        return "kimi_code_managed_account"
    if scope == "candidate":
        return "kimi_code_candidate_failure"
    return "kimi_code_no_cooldown"


def _build_safe_kimi_code_selection_telemetry(
    *,
    alias_model: str,
    candidate: dict[str, Any],
    metadata: dict[str, Any],
) -> dict[str, Any]:
    """Build an alias-attempt record without copying provider payload details."""

    return {
        "alias": alias_model,
        "candidate": candidate["model"],
        "upstream_id": metadata["upstream_id"],
        "metadata_gate": metadata["metadata_gate"],
        "scope": metadata["scope"],
        "reset_reason": metadata["reset_reason"],
        "kind": metadata["kind"],
        "status_code": metadata["status_code"],
        "trace_id": metadata["trace_id"],
    }


def _is_codex_auto_agent_transient_internal_error_class(
    error_class: Optional[str],
) -> bool:
    # Classifier emits upstream_transient_internal only; do not accept a dead alias.
    return error_class == "upstream_transient_internal"


def _get_codex_auto_agent_native_grok_continuation_transient_max_attempts() -> int:
    """Request-scoped total provider attempts for native Grok continuation retries.

    Independent of alias candidate-pool length and preserved across outer
    candidate-selection re-entry within the same request. Default 8 so bursts
    of 3-6 terminal-event 502s can recover without switching providers.
    """
    raw_value = _clean_codex_auth_value(
        os.getenv(_CODEX_AUTO_AGENT_NATIVE_GROK_CONTINUATION_TRANSIENT_MAX_ATTEMPTS_ENV)
    )
    if raw_value is None:
        return _CODEX_AUTO_AGENT_NATIVE_GROK_CONTINUATION_TRANSIENT_MAX_ATTEMPTS
    try:
        parsed = int(raw_value)
    except Exception:
        return _CODEX_AUTO_AGENT_NATIVE_GROK_CONTINUATION_TRANSIENT_MAX_ATTEMPTS
    # Conservative clamp: never drop below 6 (live aawm-code pool size) and
    # never allow unbounded same-candidate storms.
    return max(6, min(16, parsed))


def _get_codex_auto_agent_native_grok_continuation_transient_backoff_seconds(
    failed_attempt: int,
) -> float:
    """Short exponential backoff with bounded jitter; each delay capped near 1s."""
    attempt_index = max(1, int(failed_attempt))
    base_seconds = min(
        _CODEX_AUTO_AGENT_NATIVE_GROK_CONTINUATION_TRANSIENT_BACKOFF_MAX_SECONDS,
        _CODEX_AUTO_AGENT_NATIVE_GROK_CONTINUATION_TRANSIENT_BACKOFF_BASE_SECONDS * (2 ** (attempt_index - 1)),
    )
    jitter_cap = min(
        _CODEX_AUTO_AGENT_NATIVE_GROK_CONTINUATION_TRANSIENT_BACKOFF_JITTER_SECONDS,
        base_seconds,
    )
    jitter_seconds = random.uniform(0.0, jitter_cap) if jitter_cap > 0 else 0.0
    return min(
        _CODEX_AUTO_AGENT_NATIVE_GROK_CONTINUATION_TRANSIENT_BACKOFF_MAX_SECONDS,
        base_seconds + jitter_seconds,
    )


def _is_codex_auto_agent_native_grok_continuation_transient_retry_eligible(
    *,
    is_native_grok_4_5_candidate: bool,
    has_continuation_state: bool,
    error_class: Optional[str],
    cooldown_scope: Optional[str],
) -> bool:
    """Whether this failure may consume the native Grok continuation transient budget.

    Deliberately excludes ``candidate_unavailable`` even when native Grok 4.5 uses
    cooldown scope ``none`` for that class. Generic probe/credential unavailability
    must not enter the same-candidate 502-style retry budget; only bare transient
    internal failures (``upstream_transient_internal``) are eligible.
    """
    # Keep this allow-list tight: do not treat candidate_unavailable as eligible.
    return bool(
        has_continuation_state
        and cooldown_scope == "none"
        and is_native_grok_4_5_candidate
        and _is_codex_auto_agent_transient_internal_error_class(error_class)
    )


def _build_codex_auto_agent_native_grok_continuation_retry_metadata(
    *,
    status: str,
    provider_attempt: int,
    max_attempts: int,
    provider: Optional[str],
    model: Optional[str],
    route_family: Optional[str],
    backoff_seconds: Optional[float] = None,
) -> _NativeGrokContinuationRetryMetadata:
    metadata: _NativeGrokContinuationRetryMetadata = {
        "status": status,
        "provider_attempt": int(provider_attempt),
        "max_attempts": int(max_attempts),
        "provider": provider,
        "model": model,
        "route_family": route_family,
    }
    if backoff_seconds is not None:
        metadata["backoff_seconds"] = round(float(backoff_seconds), 3)
    return metadata


def _plan_codex_auto_agent_native_grok_continuation_transient_retry(
    *,
    is_native_grok_4_5_candidate: bool,
    has_continuation_state: bool,
    error_class: Optional[str],
    cooldown_scope: Optional[str],
    provider_attempt: int,
    provider: Optional[str],
    model: Optional[str],
    route_family: Optional[str],
    max_attempts: Optional[int] = None,
) -> tuple[
    bool,
    Optional[float],
    Optional[_NativeGrokContinuationRetryMetadata],
]:
    """Annotate attempt metadata and decide whether to retry the same candidate.

    ``provider_attempt`` must be the request-scoped total of eligible native Grok
    continuation transient provider attempts so far (not reset on outer
    candidate-selection re-entry). Backoff is only returned when a same-candidate
    retry is scheduled; callers must not sleep after the final failed attempt.
    """
    if not _is_codex_auto_agent_native_grok_continuation_transient_retry_eligible(
        is_native_grok_4_5_candidate=is_native_grok_4_5_candidate,
        has_continuation_state=has_continuation_state,
        error_class=error_class,
        cooldown_scope=cooldown_scope,
    ):
        return False, None, None

    resolved_max_attempts = (
        int(max_attempts)
        if max_attempts is not None
        else _get_codex_auto_agent_native_grok_continuation_transient_max_attempts()
    )
    if provider_attempt < resolved_max_attempts:
        backoff_seconds = _get_codex_auto_agent_native_grok_continuation_transient_backoff_seconds(provider_attempt)
        metadata = _build_codex_auto_agent_native_grok_continuation_retry_metadata(
            status="scheduled_same_candidate_retry",
            provider_attempt=provider_attempt,
            max_attempts=resolved_max_attempts,
            provider=provider,
            model=model,
            route_family=route_family,
            backoff_seconds=backoff_seconds,
        )
        return True, backoff_seconds, metadata

    metadata = _build_codex_auto_agent_native_grok_continuation_retry_metadata(
        status="same_candidate_retry_exhausted",
        provider_attempt=provider_attempt,
        max_attempts=resolved_max_attempts,
        provider=provider,
        model=model,
        route_family=route_family,
    )
    return False, None, metadata


def _get_codex_auto_agent_cooldown_scope(error_class: Optional[str]) -> str:
    if _is_codex_auto_agent_durable_cooldown_error_class(error_class):
        return "candidate"
    return "request_local"


def _get_codex_auto_agent_candidate_cooldown_scope(
    error_class: Optional[str],
    *,
    candidate: Optional[dict[str, Any]] = None,
    kimi_failure_metadata: Optional[dict[str, Any]] = None,
) -> str:
    if _is_kimi_code_auto_agent_candidate(candidate):
        if (
            error_class == "kimi_code_managed_account"
            and kimi_failure_metadata is not None
            and kimi_failure_metadata.get("scope") == "managed_account"
        ):
            return "managed_account"
        if (
            error_class == "kimi_code_candidate_failure"
            and kimi_failure_metadata is not None
            and kimi_failure_metadata.get("scope") == "candidate"
        ):
            return "candidate"
        if error_class == "kimi_code_no_cooldown":
            return "none"
    if error_class == "safety_policy_denied":
        return "request_local"
    # Native Grok 4.5 is live. Broad candidate-unavailable probes can still
    # happen on transient/request-shape blips, so do not evict the native
    # candidate from routing. Other xAI alias candidates (Composer, Grok Build,
    # managed OAuth Grok 4.5, etc.) stay request-local so missing/refreshing
    # credentials cannot leave multi-hour Redis candidate cooldowns.
    # Explicit rate-limit / capacity / quota classes still use candidate scope.
    if error_class == "candidate_unavailable" and _is_codex_auto_agent_native_grok_4_5_candidate(candidate):
        return "none"
    if error_class == "candidate_unavailable" and _is_codex_auto_agent_xai_candidate(candidate):
        return "request_local"
    # Native Grok 4.5 malformed tool-call text remains rejected and can still
    # redispatch in-flight, but must not write a durable candidate cooldown.
    # Composer / Grok Build / non-native candidates keep durable candidate
    # cooldowns for this class.
    if error_class == "malformed_tool_call_text" and _is_codex_auto_agent_native_grok_4_5_candidate(candidate):
        return "request_local"
    if _is_codex_auto_agent_native_grok_4_5_candidate(
        candidate
    ) and _is_codex_auto_agent_transient_internal_error_class(error_class):
        return "none"
    if _is_codex_auto_agent_spark_candidate(candidate) and _is_codex_auto_agent_transient_internal_error_class(
        error_class
    ):
        return "candidate"
    return _get_codex_auto_agent_cooldown_scope(error_class)


def _aawm_alias_route_verbose_json_enabled() -> bool:
    return os.getenv(_AAWM_ALIAS_ROUTE_VERBOSE_JSON_ENV, "").strip().lower() in {
        "1",
        "true",
        "yes",
        "debug",
        "verbose",
    }


def _aawm_alias_route_healthy_json_enabled() -> bool:
    return os.getenv("AAWM_ALIAS_ROUTE_LOG_HEALTHY", "").strip().lower() in {
        "1",
        "true",
        "yes",
    }


def _get_codex_auto_agent_request_local_cooldown_key(
    *,
    candidate: dict[str, Any],
    lane_key: Optional[str],
) -> str:
    return _codex_auto_agent_candidate_key(
        candidate,
        lane_key or "__default__",
    )


def _get_codex_auto_agent_request_local_cooldown_state(
    request: Request,
) -> dict[str, float]:
    state = getattr(request.state, "aawm_alias_request_local_cooldown_until", None)
    if isinstance(state, dict):
        return state
    state = {}
    setattr(request.state, "aawm_alias_request_local_cooldown_until", state)
    return state


def _get_codex_auto_agent_request_local_cooldown_seconds(
    request: Request,
    *,
    cooldown_key: str,
) -> float:
    until = _get_codex_auto_agent_request_local_cooldown_state(request).get(
        cooldown_key,
        0.0,
    )
    remaining = max(0.0, until - time.monotonic())
    if remaining <= 0:
        _get_codex_auto_agent_request_local_cooldown_state(request).pop(
            cooldown_key,
            None,
        )
        return 0.0
    return remaining


def _set_codex_auto_agent_request_local_cooldown(
    request: Request,
    *,
    cooldown_key: str,
    cooldown_seconds: float,
) -> None:
    ttl_seconds = max(0.0, float(cooldown_seconds))
    if ttl_seconds <= 0:
        return
    until = time.monotonic() + ttl_seconds
    state = _get_codex_auto_agent_request_local_cooldown_state(request)
    current_until = state.get(cooldown_key, 0.0)
    if until > current_until:
        state[cooldown_key] = until


def _get_codex_auto_agent_request_local_excluded_keys(
    request: Request,
) -> set[str]:
    excluded = getattr(request.state, "aawm_alias_request_local_excluded_keys", None)
    if isinstance(excluded, set):
        return excluded
    excluded = set()
    setattr(request.state, "aawm_alias_request_local_excluded_keys", excluded)
    return excluded


def _exclude_codex_auto_agent_request_local_candidate(
    request: Request,
    *,
    cooldown_key: str,
) -> None:
    _get_codex_auto_agent_request_local_excluded_keys(request).add(cooldown_key)


def _exclude_codex_auto_agent_request_local_candidate_without_cooldown(
    request: Request,
    *,
    candidate: dict[str, Any],
    lane_key: Optional[str],
) -> None:
    _exclude_codex_auto_agent_request_local_candidate(
        request,
        cooldown_key=_get_codex_auto_agent_request_local_cooldown_key(
            candidate=candidate,
            lane_key=lane_key,
        ),
    )


async def _apply_auto_agent_alias_cooldown(
    *,
    request: Request,
    candidate: Payload,
    lane_key: Optional[str],
    selected_cooldown_key: str,
    cooldown_seconds: float,
    error_class: Optional[str],
    set_candidate_cooldown: Callable[[str, float], Awaitable[object]],
    grok_account_quota_exhausted: bool = False,
    kimi_failure_metadata: Optional[dict[str, Any]] = None,
) -> str:
    """Shared auto-agent cooldown apply (RR-054 #12).

    Codex and Anthropic families share scope resolution and request-local
    exclusion; only the durable candidate setter differs.
    """
    cooldown_scope = _get_codex_auto_agent_candidate_cooldown_scope(
        error_class,
        candidate=candidate,
        kimi_failure_metadata=kimi_failure_metadata,
    )
    if cooldown_scope == "none":
        return cooldown_scope
    if cooldown_scope == "managed_account":
        await set_candidate_cooldown(
            _get_kimi_code_managed_account_cooldown_key(),
            cooldown_seconds,
        )
        return cooldown_scope
    if cooldown_scope == "candidate":
        await set_candidate_cooldown(
            selected_cooldown_key,
            cooldown_seconds,
        )
        if grok_account_quota_exhausted:
            lane_cooldown_key = _get_codex_auto_agent_grok_account_quota_lane_cooldown_key(
                candidate,
                lane_key,
            )
            if lane_cooldown_key is not None and lane_cooldown_key != selected_cooldown_key:
                await set_candidate_cooldown(
                    lane_cooldown_key,
                    cooldown_seconds,
                )
        return cooldown_scope

    request_local_key = _get_codex_auto_agent_request_local_cooldown_key(
        candidate=candidate,
        lane_key=lane_key,
    )
    _set_codex_auto_agent_request_local_cooldown(
        request,
        cooldown_key=request_local_key,
        cooldown_seconds=cooldown_seconds,
    )
    _exclude_codex_auto_agent_request_local_candidate(
        request,
        cooldown_key=request_local_key,
    )
    return cooldown_scope


_READ_PILOT_COOLDOWN_KEY_PREFIX = "read_pilot:"


async def _apply_codex_auto_agent_alias_cooldown(
    *,
    request: Request,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    selected_cooldown_key: str,
    cooldown_seconds: float,
    error_class: Optional[str],
    grok_account_quota_exhausted: bool = False,
    kimi_failure_metadata: Optional[dict[str, Any]] = None,
    is_read_pilot_lane: bool = False,
) -> str:
    # Route the read-alias lane to the N-of-M evidence gate by ALIAS identity
    # (``is_read_pilot_lane``), not by a synthetic ``read_pilot:`` key prefix.
    # The live selector builds ordinary ``provider:model:lane`` cooldown keys,
    # so the gate now drives the applied cooldown for the read lane using that
    # exact live key -- the same key the retry loop fed evidence to.
    if is_read_pilot_lane:
        return await _apply_read_pilot_gated_cooldown(
            selected_cooldown_key=selected_cooldown_key,
            set_candidate_cooldown=_set_codex_auto_agent_cooldown,
        )
    return await _apply_auto_agent_alias_cooldown(
        request=request,
        candidate=candidate,
        lane_key=lane_key,
        selected_cooldown_key=selected_cooldown_key,
        cooldown_seconds=cooldown_seconds,
        error_class=error_class,
        set_candidate_cooldown=_set_codex_auto_agent_cooldown,
        grok_account_quota_exhausted=grok_account_quota_exhausted,
        kimi_failure_metadata=kimi_failure_metadata,
    )


async def _apply_read_pilot_gated_cooldown(
    *,
    selected_cooldown_key: str,
    set_candidate_cooldown: Callable[[str, float], Awaitable[object]],
) -> str:
    """Apply the ``CooldownEvidenceGate``'s decision for the read-pilot lane.

    The read-pilot lane's cooldown-worthiness is decided by
    ``_read_pilot_cooldown_gate`` (fed via ``_record_read_pilot_cooldown_evidence``
    on failure). This makes that decision authoritative for what cooldown is
    actually applied -- when the gate says "do not cool yet" (marker-only
    evidence below the N-of-M threshold, or a non-coolable origin), no
    cooldown is applied at all; when it says cool, the gate's own
    duration/scope drives the applied candidate cooldown instead of the
    legacy flat ``cooldown_seconds`` value.
    """
    decision = _read_pilot_cooldown_gate.current_decision(cooldown_key=selected_cooldown_key)
    if not decision.should_cool:
        return "none"
    # Apply to the authoritative in-memory cooldown state synchronously so the
    # selector observes the full gate-resolved duration; the durable write is
    # best-effort and must not block that value.
    _alias_routing_state.codex.set_cooldown_memory(selected_cooldown_key, decision.duration_seconds)
    asyncio.ensure_future(set_candidate_cooldown(selected_cooldown_key, decision.duration_seconds))
    return decision.scope or "candidate"


async def _apply_anthropic_auto_agent_alias_cooldown(
    *,
    request: Request,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    selected_cooldown_key: str,
    cooldown_seconds: float,
    error_class: Optional[str],
    grok_account_quota_exhausted: bool = False,
    kimi_failure_metadata: Optional[dict[str, Any]] = None,
    is_read_pilot_lane: bool = False,
) -> str:
    # The read pilot lane is Codex-only; the Anthropic applicator accepts the
    # flag for call-site symmetry with the shared retry loop and ignores it.
    _ = is_read_pilot_lane
    return await _apply_auto_agent_alias_cooldown(
        request=request,
        candidate=candidate,
        lane_key=lane_key,
        selected_cooldown_key=selected_cooldown_key,
        cooldown_seconds=cooldown_seconds,
        error_class=error_class,
        set_candidate_cooldown=_set_anthropic_auto_agent_cooldown,
        grok_account_quota_exhausted=grok_account_quota_exhausted,
        kimi_failure_metadata=kimi_failure_metadata,
    )


def _is_codex_auto_agent_grok_build_usage_balance_exhausted(exc: Any) -> bool:
    status_code = _extract_google_adapter_exception_status_code(exc)
    return _is_known_grok_build_usage_balance_exhausted_response(
        url=httpx.URL(_CODEX_AUTO_AGENT_GROK_BUILD_USAGE_BALANCE_EXHAUSTED_UPSTREAM_URL),
        custom_llm_provider=litellm.LlmProviders.XAI.value,
        status_code=status_code,
        exc=exc,
    )


def _is_codex_auto_agent_grok_personal_team_spending_limit(exc: Any) -> bool:
    status_code = _extract_google_adapter_exception_status_code(exc)
    return _is_known_grok_personal_team_spending_limit_response(
        url=httpx.URL(_CODEX_AUTO_AGENT_GROK_BUILD_USAGE_BALANCE_EXHAUSTED_UPSTREAM_URL),
        custom_llm_provider=litellm.LlmProviders.XAI.value,
        status_code=status_code,
        exc=exc,
    )


def _is_codex_auto_agent_grok_account_quota_candidate(
    candidate: Optional[dict[str, Any]],
) -> bool:
    if not isinstance(candidate, dict):
        return False
    if candidate.get("provider") != _CODEX_AUTO_AGENT_XAI_PROVIDER:
        return False
    route_family = str(candidate.get("route_family") or "")
    return route_family in {
        "codex_grok_native_responses_adapter",
        "codex_xai_oauth_responses_adapter",
        "anthropic_grok_native_responses_adapter",
        "anthropic_xai_oauth_responses_adapter",
    }


def _resolve_codex_auto_agent_xai_lane_key(candidate: dict[str, Any]) -> str:
    route_family = str(candidate.get("route_family") or "")
    if route_family in {
        "codex_xai_oauth_responses_adapter",
        "anthropic_xai_oauth_responses_adapter",
    }:
        return _CODEX_AUTO_AGENT_XAI_OAUTH_LANE_KEY
    return _CODEX_AUTO_AGENT_XAI_LANE_KEY


def _get_codex_auto_agent_grok_account_quota_lane_cooldown_key(
    candidate: Payload,
    lane_key: Optional[str],
) -> Optional[str]:
    if not lane_key or not _is_codex_auto_agent_grok_account_quota_candidate(candidate):
        return None
    return f"{candidate.get('provider')}:__account_quota__:{lane_key}"


async def _apply_codex_auto_agent_grok_account_lane_cooldown(
    *,
    candidate: Payload,
    lane_key: Optional[str],
    cooldown_seconds: float,
    cooldown_state_source: Optional[str],
    skip_reason: Optional[str],
    get_active_cooldown_state: Callable[[str], Awaitable[tuple[float, str]]],
) -> tuple[float, Optional[str], Optional[str]]:
    lane_cooldown_key = _get_codex_auto_agent_grok_account_quota_lane_cooldown_key(
        candidate,
        lane_key,
    )
    if lane_cooldown_key is None:
        return cooldown_seconds, cooldown_state_source, skip_reason
    lane_seconds, lane_source = await get_active_cooldown_state(lane_cooldown_key)
    if lane_seconds > cooldown_seconds:
        cooldown_seconds = lane_seconds
        cooldown_state_source = lane_source
    if lane_seconds > 0 and skip_reason is None:
        skip_reason = "account_quota_cooldown"
    return cooldown_seconds, cooldown_state_source, skip_reason


def _is_codex_auto_agent_grok_account_quota_exhaustion(
    exc: Any,
    *,
    candidate: Optional[dict[str, Any]] = None,
) -> bool:
    if not (
        _is_codex_auto_agent_grok_build_usage_balance_exhausted(exc)
        or _is_codex_auto_agent_grok_personal_team_spending_limit(exc)
    ):
        return False
    if candidate is None:
        return True
    return _is_codex_auto_agent_grok_account_quota_candidate(candidate)


def _classify_codex_auto_agent_retryable_exhaustion(
    exc: Any,
) -> Optional[str]:
    status_code = _extract_google_adapter_exception_status_code(exc)
    tokens = _extract_codex_auto_agent_error_tokens(exc)
    if _is_codex_auto_agent_grok_account_quota_exhaustion(exc):
        return "capacity_exhausted"
    if "usage_limit_reached" in tokens:
        return "usage_limit_reached"
    if tokens & _CODEX_AUTO_AGENT_CAPACITY_ERROR_TOKENS:
        return "capacity_exhausted"
    if tokens & _CODEX_AUTO_AGENT_RATE_LIMIT_ERROR_TOKENS:
        return "rate_limited"
    if "aawm_codex_auto_agent_candidate_unavailable" in tokens:
        return "candidate_unavailable"
    if "DEEPSEEK_TOOL_MESSAGE_MISMATCH" in tokens:
        return "provider_format_rejected"
    if "OPENROUTER_INVALID_CHAT_MESSAGE" in tokens:
        return "provider_format_rejected"
    if "OPENROUTER_INVALID_TOOL_CALL_ARGUMENTS" in tokens:
        return "provider_format_rejected"
    if "OPENROUTER_PROVIDER_RAW_ERROR" in tokens:
        return "provider_terminal_error"
    if "aawm_auto_agent_failed_responses_payload" in tokens:
        return "provider_terminal_error"
    if "aawm_auto_agent_malformed_tool_call_text" in tokens:
        return "malformed_tool_call_text"
    if "safety_policy_denied" in tokens:
        return "safety_policy_denied"
    if status_code == 429:
        return "rate_limited"
    if status_code in _CODEX_AUTO_AGENT_TRANSIENT_UPSTREAM_STATUS_CODES:
        return "upstream_transient_internal"
    if status_code == 504:
        return "upstream_timeout"
    return None


def _is_codex_auto_agent_retryable_exhaustion(exc: Any) -> bool:
    return _classify_codex_auto_agent_retryable_exhaustion(exc) is not None


def _parse_codex_auto_agent_header_wait_seconds(exc: Any) -> Optional[float]:
    headers = _extract_adapter_upstream_headers(exc)
    retry_after = _parse_retry_after_seconds_from_headers(headers)
    if retry_after is not None:
        return max(1.0, retry_after)

    wait_candidates: list[float] = []
    for header_name in (
        "X-RateLimit-Reset",
        "x-ratelimit-reset",
        "x-codex-primary-reset-at",
        "x-codex-secondary-reset-at",
        "x-codex-bengalfox-primary-reset-at",
        "x-codex-bengalfox-secondary-reset-at",
    ):
        reset_value = _get_adapter_header_value(headers, header_name)
        if reset_value is None:
            continue
        try:
            reset_number = float(reset_value)
        except Exception:
            continue
        if reset_number > 1_000_000_000_000:
            reset_epoch_seconds = reset_number / 1000.0
        else:
            reset_epoch_seconds = reset_number
        wait_candidates.append(max(1.0, reset_epoch_seconds - time.time()))
    if not wait_candidates:
        return None
    return min(wait_candidates)


def _get_codex_auto_agent_cooldown_seconds(
    exc: Any,
    *,
    candidate: Optional[dict[str, Any]] = None,
) -> float:
    header_wait = _parse_codex_auto_agent_header_wait_seconds(exc)
    error_class = _classify_codex_auto_agent_retryable_exhaustion(exc)
    tokens = _extract_codex_auto_agent_error_tokens(exc)
    if header_wait is not None:
        resolved = max(_CODEX_AUTO_AGENT_DEFAULT_COOLDOWN_SECONDS, header_wait)
    elif (
        error_class in {"capacity_exhausted", "upstream_overloaded"} or tokens & _CODEX_AUTO_AGENT_CAPACITY_ERROR_TOKENS
    ):
        resolved = _CODEX_AUTO_AGENT_DEFAULT_CAPACITY_COOLDOWN_SECONDS
    elif _is_codex_auto_agent_transient_internal_error_class(error_class):
        resolved = _CODEX_AUTO_AGENT_DEFAULT_TRANSIENT_COOLDOWN_SECONDS
    elif "usage_limit_reached" in tokens:
        resolved = _CODEX_AUTO_AGENT_DEFAULT_USAGE_LIMIT_COOLDOWN_SECONDS
    elif error_class == "malformed_tool_call_text":
        resolved = _CODEX_AUTO_AGENT_MALFORMED_TOOL_CALL_COOLDOWN_SECONDS
    elif "RESOURCE_EXHAUSTED" in tokens or "RATE_LIMIT_EXCEEDED" in tokens:
        resolved = _CODEX_AUTO_AGENT_DEFAULT_RATE_LIMIT_COOLDOWN_SECONDS
    elif _extract_google_adapter_exception_status_code(exc) in {429, 503, 529}:
        resolved = _CODEX_AUTO_AGENT_DEFAULT_RATE_LIMIT_COOLDOWN_SECONDS
    else:
        resolved = _CODEX_AUTO_AGENT_DEFAULT_CAPACITY_COOLDOWN_SECONDS

    if _is_codex_auto_agent_spark_candidate(candidate) and _is_codex_auto_agent_durable_cooldown_error_class(
        error_class
    ):
        return _CODEX_AUTO_AGENT_SPARK_DURABLE_COOLDOWN_SECONDS
    if _is_codex_auto_agent_grok_account_quota_exhaustion(
        exc,
        candidate=candidate,
    ) and _is_codex_auto_agent_durable_cooldown_error_class(error_class):
        return _CODEX_AUTO_AGENT_GROK_ACCOUNT_QUOTA_DURABLE_COOLDOWN_SECONDS
    return resolved


def _iter_codex_auto_agent_error_blocks(exc: Any) -> list[dict[str, Any]]:
    payloads: list[Any] = []
    detail = getattr(exc, "detail", None)
    if detail is not None:
        payloads.append(detail)
    payloads.extend(_extract_google_adapter_error_payloads(exc))

    error_blocks: list[dict[str, Any]] = []
    for parsed in payloads:
        if isinstance(parsed, dict):
            error = parsed.get("error")
            if isinstance(error, dict):
                error_blocks.append(error)
        elif isinstance(parsed, list):
            error_blocks.extend(
                item["error"] for item in parsed if isinstance(item, dict) and isinstance(item.get("error"), dict)
            )
    return error_blocks


def _extract_codex_auto_agent_error_type_and_code(
    exc: Any,
) -> tuple[Optional[str], Optional[Any]]:
    fallback_error_type = _clean_codex_auth_value(getattr(exc, "type", None))
    fallback_error_code: Optional[Any] = getattr(exc, "code", None)
    error_type: Optional[str] = None
    error_code: Optional[Any] = None
    for error in _iter_codex_auto_agent_error_blocks(exc):
        if error_type is None:
            error_type = _clean_codex_auth_value(error.get("type") or error.get("status"))
        if error_code is None:
            error_code = error.get("code") or error.get("status")
        if error_type is not None and error_code is not None:
            return error_type, error_code
    return error_type or fallback_error_type, error_code or fallback_error_code


async def _set_codex_auto_agent_candidate_cooldowns(
    *,
    request: Request,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    selected_cooldown_key: str,
    cooldown_seconds: float,
    error_class: Optional[str],
    grok_account_quota_exhausted: bool = False,
    kimi_failure_metadata: Optional[dict[str, Any]] = None,
    is_read_pilot_lane: bool = False,
) -> str:
    return await _apply_codex_auto_agent_alias_cooldown(
        request=request,
        candidate=candidate,
        lane_key=lane_key,
        selected_cooldown_key=selected_cooldown_key,
        cooldown_seconds=cooldown_seconds,
        error_class=error_class,
        grok_account_quota_exhausted=grok_account_quota_exhausted,
        kimi_failure_metadata=kimi_failure_metadata,
        is_read_pilot_lane=is_read_pilot_lane,
    )


def _get_codex_auto_agent_source_error_summary(
    exc: Any,
    *,
    status_code: Optional[int],
) -> str:
    raw_message = _extract_openrouter_adapter_raw_message(exc)
    if isinstance(raw_message, str) and raw_message:
        for parsed in _parse_json_payloads_from_text_candidates([raw_message]):
            if not isinstance(parsed, dict):
                continue
            message = parsed.get("message")
            if not isinstance(message, str):
                error = parsed.get("error")
                if isinstance(error, dict):
                    message = error.get("message")
            if isinstance(message, str) and message:
                return _get_passthrough_handled_http_error_summary(
                    HTTPException(
                        status_code=status_code or status.HTTP_502_BAD_GATEWAY,
                        detail=message,
                    ),
                    status_code=status_code,
                )
    return _get_passthrough_handled_http_error_summary(
        exc,
        status_code=status_code,
    )


def _update_codex_auto_agent_retryable_attempt_record(
    *,
    attempt_record: dict[str, Any],
    exc: Any,
    error_class: str,
    cooldown_seconds: float,
    cooldown_scope: Optional[str] = None,
    alias_model: Optional[str] = None,
    candidate: Optional[dict[str, Any]] = None,
    kimi_failure_metadata: Optional[dict[str, Any]] = None,
) -> set[str]:
    error_tokens = _extract_codex_auto_agent_error_tokens(exc)
    error_status_code = _extract_google_adapter_exception_status_code(exc)
    error_type, error_code = _extract_codex_auto_agent_error_type_and_code(exc)
    retry_after_seconds = _parse_codex_auto_agent_header_wait_seconds(exc)
    source_error = _get_codex_auto_agent_source_error_summary(
        exc,
        status_code=error_status_code,
    )
    update: dict[str, Any] = {
        "status": ("retryable_no_cooldown" if cooldown_scope == "none" else "cooldown_set"),
        "error_class": error_class,
        "error_tokens": sorted(error_tokens),
        "failure_phase": "provider_attempt",
        "attempted_provider_call": True,
        "source_error": source_error,
    }
    if cooldown_scope != "none":
        update["cooldown_seconds"] = round(float(cooldown_seconds), 3)
    if cooldown_scope is not None:
        update["cooldown_scope"] = cooldown_scope
    if error_status_code is not None:
        update["error_status_code"] = error_status_code
    if error_type is not None:
        update["error_type"] = error_type
    if error_code is not None:
        update["error_code"] = str(error_code)
    if retry_after_seconds is not None:
        update["retry_after_seconds"] = round(float(retry_after_seconds), 3)
    if alias_model is not None and candidate is not None and kimi_failure_metadata is not None:
        update["kimi_code_failure"] = _build_safe_kimi_code_selection_telemetry(
            alias_model=alias_model,
            candidate=candidate,
            metadata=kimi_failure_metadata,
        )
    attempt_record.update(update)
    return error_tokens


def _record_auto_agent_alias_attempt_started(
    *,
    alias_family: str,
    alias_model: str,
    request: Request,
    prepared_request_body: dict[str, Any],
    selection: dict[str, Any],
    attempts: list[dict[str, Any]],
    attempt_record: dict[str, Any],
    add_alias_metadata_fn: Callable[..., dict[str, Any]],
) -> dict[str, Any]:
    candidate_body = add_alias_metadata_fn(
        prepared_request_body,
        request=request,
        selection=selection,
        attempts=attempts,
    )
    _safe_set_request_parsed_body(request, candidate_body)
    candidate_metadata = candidate_body.get("litellm_metadata")
    audit_events = (
        candidate_metadata.get("aawm_alias_routing_audit_events") if isinstance(candidate_metadata, dict) else None
    )
    if (
        isinstance(audit_events, list)
        and audit_events
        and (_aawm_alias_route_verbose_json_enabled() or _aawm_alias_route_healthy_json_enabled())
    ):
        latest_event = audit_events[-1]
        if isinstance(latest_event, dict):
            _emit_auto_agent_alias_route_event(latest_event)
    return candidate_body


def _record_read_pilot_cooldown_evidence(
    *,
    cooldown_key: Optional[str],
    exc: Any,
    attempt_record: dict[str, Any],
) -> None:
    """Classify + record the CURRENT read-pilot attempt's failure evidence.

    Called from the retry loop BEFORE the cooldown is applied for the same
    attempt, so a structured failure cools immediately (N=1) and a marker
    failure counts toward its N-of-M threshold on this attempt. The evidence
    is keyed on the live ``provider:model:lane`` cooldown key so the gate and
    the applied cooldown share one authoritative key. Classification inputs
    (status code, source-error text, retry-after) are extracted directly from
    the raised exception rather than the post-apply attempt record, because
    those record fields are not populated until after the cooldown decision.

    ``origin`` (upstream/client/unknown; only ``upstream`` ever advances a key
    toward cooling) is stamped on the attempt record for downstream audit.
    """
    error_status_code = _extract_google_adapter_exception_status_code(exc)
    source_error = _get_codex_auto_agent_source_error_summary(exc, status_code=error_status_code)
    retry_after_seconds = _parse_codex_auto_agent_header_wait_seconds(exc)
    event = _aawm_alias_classification.classify_failure(
        status_code=error_status_code,
        provider=None,
        message=str(source_error or ""),
        retry_after_seconds=retry_after_seconds,
    )
    attempt_record["origin"] = event.origin
    _read_pilot_cooldown_gate.record(
        cooldown_key=cooldown_key or f"{_READ_PILOT_COOLDOWN_KEY_PREFIX}unknown",
        event=event,
    )


def _record_auto_agent_alias_attempt_failure(
    *,
    alias_family: str,
    alias_model: str,
    request: Request,
    prepared_request_body: dict[str, Any],
    selection: dict[str, Any],
    attempts: list[dict[str, Any]],
    attempt_record: dict[str, Any],
    error_class: str,
    add_alias_metadata_fn: Callable[..., dict[str, Any]],
    redispatch_required: bool = False,
) -> dict[str, Any]:
    # Read-pilot cooldown evidence is recorded in the retry loop BEFORE the
    # cooldown is applied (see ``_record_read_pilot_cooldown_evidence``), so it
    # is intentionally NOT re-recorded here -- doing so would double-count
    # marker evidence and double-advance the structured attempt counter.
    failure_body = add_alias_metadata_fn(
        prepared_request_body,
        request=request,
        selection=selection,
        attempts=attempts,
    )
    _safe_set_request_parsed_body(request, failure_body)
    failure_metadata = failure_body.get("litellm_metadata")
    full_audit_events = (
        failure_metadata.get("aawm_alias_routing_audit_events") if isinstance(failure_metadata, dict) else None
    )
    audit_events = [event for event in full_audit_events or [] if isinstance(event, dict)]
    audit_event = audit_events[-1] if audit_events else None
    if audit_event is None:
        audit_event = _build_auto_agent_alias_audit_event(
            alias_family=alias_family,
            alias_model=alias_model,
            request=request,
            request_body=prepared_request_body,
            selection=selection,
            candidate=attempt_record,
            event_type="redispatch_required" if redispatch_required else "candidate_retryable_failure",
            candidate_status=attempt_record.get("status") or "cooldown_set",
            attempt_number=len(attempts),
            selected=True,
            selection_reason=selection.get("selection_reason"),
            lane_key=selection.get("lane_key"),
            cooldown_key=selection.get("cooldown_key"),
            cooldown_seconds=attempt_record.get("cooldown_seconds"),
            cooldown_scope=attempt_record.get("cooldown_scope"),
            failure_class=error_class,
            error_status_code=attempt_record.get("error_status_code"),
            error_type=attempt_record.get("error_type"),
            error_code=attempt_record.get("error_code"),
            error_tokens=attempt_record.get("error_tokens"),
            source_error=attempt_record.get("source_error"),
            retry_after_seconds=attempt_record.get("retry_after_seconds"),
            failure_phase=attempt_record.get("failure_phase"),
            attempted_provider_call=attempt_record.get("attempted_provider_call"),
            redispatch_required=redispatch_required,
        )
        audit_events = [audit_event]
    _emit_auto_agent_alias_route_event(
        audit_event,
        level="warning",
    )
    # Only terminal redispatch outcomes use audit-only persistence. Mid-loop
    # retryable 429s that continue failover still reach a normal success or
    # no-candidate write path and must not double-write audit rows.
    if redispatch_required:
        _persist_auto_agent_alias_audit_only_events_best_effort(
            audit_events,
            request_body=prepared_request_body,
        )
    return failure_body


def _extract_codex_reasoning_effort(
    request_body: dict[str, Any],
) -> tuple[Optional[str], Optional[str]]:
    reasoning = request_body.get("reasoning")
    if isinstance(reasoning, dict) and "effort" in reasoning:
        value = reasoning.get("effort")
        return (value if isinstance(value, str) else None), "reasoning.effort"
    if "reasoning_effort" in request_body:
        value = request_body.get("reasoning_effort")
        return (value if isinstance(value, str) else None), "reasoning_effort"
    return None, None


def _get_codex_reasoning_effort_ceiling(
    resolved_route: dict[str, Any],
) -> Optional[str]:
    if (
        resolved_route.get("provider") != litellm.LlmProviders.OPENAI.value
        or resolved_route.get("route_family") != "codex_responses"
    ):
        return None

    model = resolved_route.get("model")
    if not isinstance(model, str) or not model:
        return None
    model_info_sources: list[Mapping[str, Any]] = []
    try:
        resolved_model_info = litellm.get_model_info(
            model=model,
            custom_llm_provider=litellm.LlmProviders.OPENAI.value,
        )
        if isinstance(resolved_model_info, dict):
            model_info_sources.append(resolved_model_info)
    except Exception:
        pass
    for model_cost in (
        litellm.model_cost,
        _load_bundled_model_cost_map_for_codex_policy(),
    ):
        catalog_model_info = model_cost.get(model)
        if isinstance(catalog_model_info, dict):
            model_info_sources.append(catalog_model_info)

    if any(model_info.get("supports_max_reasoning_effort") is True for model_info in model_info_sources):
        return "max"
    if any(model_info.get("supports_xhigh_reasoning_effort") is True for model_info in model_info_sources):
        return "xhigh"
    if any(model_info.get("supports_reasoning") is True for model_info in model_info_sources) and any(
        model_info.get("supports_xhigh_reasoning_effort") is False for model_info in model_info_sources
    ):
        return "high"
    return None


def _normalize_codex_reasoning_effort_for_resolved_route(
    request_body: dict[str, Any],
    *,
    resolved_route: dict[str, Any],
    attempt_number: Optional[int] = None,
) -> tuple[dict[str, Any], dict[str, Any]]:
    requested_effort, native_field = _extract_codex_reasoning_effort(request_body)
    if requested_effort not in _CODEX_REASONING_EFFORT_TIER_INDEX or native_field is None:
        return request_body, {}

    supported_ceiling = _get_codex_reasoning_effort_ceiling(resolved_route)
    if supported_ceiling is None:
        return request_body, {}

    emitted_effort = requested_effort
    mapping_reason = "within_supported_ceiling"
    if _CODEX_REASONING_EFFORT_TIER_INDEX[requested_effort] > _CODEX_REASONING_EFFORT_TIER_INDEX[supported_ceiling]:
        emitted_effort = supported_ceiling
        mapping_reason = "requested_effort_above_model_supported_ceiling"

    updated_body = dict(request_body)
    if emitted_effort != requested_effort:
        if native_field == "reasoning.effort":
            reasoning = dict(updated_body.get("reasoning") or {})
            reasoning["effort"] = emitted_effort
            updated_body["reasoning"] = reasoning
        else:
            updated_body["reasoning_effort"] = emitted_effort

    litellm_metadata = dict(updated_body.get("litellm_metadata") or {})
    existing_tags = litellm_metadata.get("tags")
    if isinstance(existing_tags, list):
        litellm_metadata["tags"] = [
            tag
            for tag in existing_tags
            if not (
                isinstance(tag, str)
                and (
                    tag == "reasoning-effort-clamped"
                    or tag.startswith("codex-effort:")
                    or tag.startswith("effort:")
                    or tag.startswith("reasoning-effort-ceiling:")
                    or tag.startswith("reasoning-effort-map:")
                    or tag.startswith("codex-auto-agent-attempt:")
                )
            )
        ]
    updated_body["litellm_metadata"] = litellm_metadata

    provider = str(resolved_route["provider"])
    model = str(resolved_route["model"])
    mapping_metadata: dict[str, Any] = {
        "codex_reasoning_effort": emitted_effort,
        "reasoning_effort_requested": requested_effort,
        "reasoning_effort_source": native_field,
        "reasoning_effort_native_provider": provider,
        "reasoning_effort_native_value": emitted_effort,
        "reasoning_effort_native_field": native_field,
        "reasoning_effort_supported_ceiling": supported_ceiling,
        "reasoning_effort_resolved_model": model,
        "reasoning_effort_resolved_provider": provider,
        "reasoning_effort_mapping_reason": mapping_reason,
        "openai_reasoning_effort": emitted_effort,
    }
    tags_to_add = [
        f"codex-effort:{emitted_effort}",
        f"effort:{emitted_effort}",
        f"reasoning-effort-ceiling:{supported_ceiling}",
    ]
    if attempt_number is not None:
        mapping_metadata["reasoning_effort_candidate_attempt"] = attempt_number
        tags_to_add.append(f"codex-auto-agent-attempt:{attempt_number}")
    if emitted_effort != requested_effort:
        mapping_metadata.update(
            {
                "reasoning_effort_clamped_from": requested_effort,
                "reasoning_effort_clamp_reason": mapping_reason,
            }
        )
        tags_to_add.extend(
            [
                "reasoning-effort-clamped",
                f"reasoning-effort-map:{requested_effort}-to-{emitted_effort}",
            ]
        )

    return (
        _merge_litellm_metadata(
            updated_body,
            tags_to_add=tags_to_add,
            extra_fields=mapping_metadata,
        ),
        mapping_metadata,
    )


def _add_codex_auto_agent_alias_metadata(
    request_body: dict[str, Any],
    *,
    request: Request,
    selection: dict[str, Any],
    attempts: list[dict[str, Any]],
) -> dict[str, Any]:
    candidate = selection["candidate"]
    alias_model = (
        selection.get("alias_model")
        or _normalize_codex_auto_agent_alias_model(request_body.get("model"))
        or _CODEX_AUTO_AGENT_MODEL_ALIAS
    )
    target_model = candidate["model"]
    updated_body = copy.deepcopy(request_body)
    updated_body["model"] = target_model
    default_reasoning_effort = _normalize_low_cardinality_tag_value(candidate.get("default_reasoning_effort"))
    default_reasoning_applied = False
    if default_reasoning_effort and "reasoning_effort" not in updated_body:
        reasoning = updated_body.get("reasoning")
        if not isinstance(reasoning, dict):
            updated_body["reasoning"] = {"effort": default_reasoning_effort}
            default_reasoning_applied = True
        elif not reasoning.get("effort"):
            updated_body["reasoning"] = {
                **reasoning,
                "effort": default_reasoning_effort,
            }
            default_reasoning_applied = True
    attempt_number = max(1, len(attempts))
    (
        updated_body,
        reasoning_effort_metadata,
    ) = _normalize_codex_reasoning_effort_for_resolved_route(
        updated_body,
        resolved_route=candidate,
        attempt_number=attempt_number,
    )
    audit_selection = selection
    if reasoning_effort_metadata:
        if attempts:
            attempts[-1].update(reasoning_effort_metadata)
        else:
            audit_selection = {
                **selection,
                "candidate": {
                    **candidate,
                    **reasoning_effort_metadata,
                },
            }
    skipped = selection.get("skipped") or []
    audit_events = _build_auto_agent_alias_audit_events(
        alias_family="codex_auto_agent",
        alias_model=alias_model,
        request=request,
        request_body=request_body,
        selection=audit_selection,
        attempts=attempts,
    )
    return _merge_litellm_metadata(
        updated_body,
        tags_to_add=[
            "codex-auto-agent-alias",
            f"codex-auto-agent-selected:{target_model}",
            f"codex-auto-agent-route:{candidate['route_family']}",
            f"model-alias:{alias_model}",
            *(["codex-auto-agent-last-resort"] if candidate.get("last_resort") else []),
            *([f"codex-auto-agent-default-effort:{default_reasoning_effort}"] if default_reasoning_applied else []),
            f"codex-auto-agent-alias:{alias_model}",
        ],
        extra_fields={
            "model_alias_label": alias_model,
            "requested_model_alias": alias_model,
            "codex_auto_agent_alias": alias_model,
            "codex_auto_agent_selected_provider": candidate["provider"],
            "codex_auto_agent_selected_model": target_model,
            "codex_auto_agent_selected_route_family": candidate["route_family"],
            "codex_auto_agent_selected_last_resort": bool(candidate.get("last_resort")),
            **(
                {
                    "codex_auto_agent_default_reasoning_effort": (default_reasoning_effort),
                    "codex_reasoning_effort": (
                        reasoning_effort_metadata.get("codex_reasoning_effort") or default_reasoning_effort
                    ),
                }
                if default_reasoning_applied
                else {}
            ),
            "codex_auto_agent_selection_reason": selection.get("selection_reason"),
            "codex_auto_agent_affinity_state_source": selection.get("affinity_state_source"),
            "codex_auto_agent_cooldown_state_source": selection.get("cooldown_state_source"),
            "codex_auto_agent_lane_key": selection.get("lane_key"),
            "codex_auto_agent_attempts": attempts,
            "codex_auto_agent_skipped_candidates": skipped,
            "codex_auto_agent_audit_events": audit_events,
            "aawm_alias_routing_audit_events": audit_events,
        },
    )


def _normalize_anthropic_auto_agent_alias_model(model: Any) -> Optional[str]:
    if not isinstance(model, str):
        return None
    normalized = model.strip().lower()
    for alias in _ANTHROPIC_AUTO_AGENT_CANDIDATES_BY_ALIAS:
        if normalized == alias.lower():
            return alias
    return None


def _is_anthropic_auto_agent_alias_model(model: Any) -> bool:
    return _normalize_anthropic_auto_agent_alias_model(model) is not None


def _resolve_anthropic_auto_agent_alias_model(
    request_body: dict[str, Any],
    endpoint: str,
) -> Optional[str]:
    if not _has_anthropic_responses_adapter_endpoint(endpoint):
        return None
    return _normalize_anthropic_auto_agent_alias_model(request_body.get("model"))


def _resolve_anthropic_auto_agent_native_lane_key(
    request: Request,
    *,
    include_session_fallback: bool = True,
) -> str:
    headers = _safe_get_request_headers(request)
    for header_name in ("x-api-key", "authorization"):
        header_value = _get_codex_auto_agent_header(headers, header_name)
        if header_value is not None:
            return f"{header_name}:{_hash_codex_auto_agent_lane_value(header_value)}"
    if include_session_fallback:
        session_header = (
            _get_codex_auto_agent_header(headers, "session_id")
            or _get_codex_auto_agent_header(headers, "session-id")
            or _get_codex_auto_agent_header(headers, "x-session-id")
        )
        if session_header is not None:
            return f"session:{session_header}"
    return "__default__"


def _resolve_anthropic_auto_agent_native_cooldown_lane_key(request: Request) -> str:
    return _resolve_anthropic_auto_agent_native_lane_key(
        request,
        include_session_fallback=False,
    )


def _resolve_anthropic_auto_agent_session_key(
    request: Request,
    request_body: dict[str, Any],
    *,
    alias_model: str = _ANTHROPIC_AUTO_AGENT_MODEL_ALIAS,
) -> Optional[str]:
    metadata = request_body.get("litellm_metadata")
    metadata_session_id = metadata.get("session_id") if isinstance(metadata, dict) else None
    session_id = _clean_codex_auth_value(metadata_session_id)
    headers = _safe_get_request_headers(request)
    if session_id is None:
        session_id = (
            _get_codex_auto_agent_header(headers, "session_id")
            or _get_codex_auto_agent_header(headers, "session-id")
            or _get_codex_auto_agent_header(headers, "x-session-id")
        )
    if session_id is None:
        return None
    if alias_model == _ANTHROPIC_AUTO_AGENT_MODEL_ALIAS:
        return f"{session_id}:{_resolve_anthropic_auto_agent_native_lane_key(request)}"
    return f"{alias_model}:{session_id}:" f"{_resolve_anthropic_auto_agent_native_lane_key(request)}"


def _format_merged_alias_family_cooldown_state_source(
    *,
    anthropic_seconds: float,
    anthropic_source: str,
    codex_seconds: float,
    codex_source: str,
) -> tuple[float, str]:
    family_states: list[tuple[float, str]] = []
    if anthropic_seconds > 0:
        family_states.append(
            (
                anthropic_seconds,
                f"anthropic_family:{anthropic_source}",
            )
        )
    if codex_seconds > 0:
        family_states.append((codex_seconds, f"codex_family:{codex_source}"))
    if not family_states:
        return 0.0, "local_fallback"
    family_states.sort(key=lambda item: item[0], reverse=True)
    merged_seconds = family_states[0][0]
    merged_source = "+".join(source for _, source in family_states)
    return merged_seconds, merged_source


async def _get_anthropic_auto_agent_merged_codex_openai_cooldown_state(
    cooldown_key: str,
) -> tuple[float, str]:
    (
        anthropic_seconds,
        anthropic_source,
    ) = await _get_anthropic_auto_agent_active_cooldown_state(cooldown_key)
    codex_seconds, codex_source = await _get_codex_auto_agent_active_cooldown_state(cooldown_key)
    return _format_merged_alias_family_cooldown_state_source(
        anthropic_seconds=anthropic_seconds,
        anthropic_source=anthropic_source,
        codex_seconds=codex_seconds,
        codex_source=codex_source,
    )


async def _get_anthropic_auto_agent_active_cooldown_state(
    cooldown_key: str,
) -> tuple[float, str]:
    async with _anthropic_auto_agent_lock:
        now = time.monotonic()
        until = _anthropic_auto_agent_cooldown_until_monotonic_by_key.get(cooldown_key, 0.0)
        if until > now:
            return max(0.0, until - now), "memory"
        _anthropic_auto_agent_cooldown_until_monotonic_by_key.pop(cooldown_key, None)
        neg_until = _anthropic_auto_agent_cooldown_negative_until_monotonic_by_key.get(cooldown_key, 0.0)
        if neg_until > now:
            return 0.0, "negative_cache"
    dual_cache = _get_aawm_alias_routing_dual_cache()
    if dual_cache is None:
        return 0.0, "local_fallback"
    durable_payload = await _read_aawm_alias_routing_durable_payload(
        alias_family="anthropic",
        state_kind="cooldown",
        state_key=cooldown_key,
    )
    if durable_payload is None:
        async with _anthropic_auto_agent_lock:
            _anthropic_auto_agent_cooldown_negative_until_monotonic_by_key[cooldown_key] = (
                time.monotonic() + _AAWM_COOLDOWN_NEGATIVE_CACHE_TTL_SECONDS
            )
            _bound_aawm_alias_routing_memory_map(_anthropic_auto_agent_cooldown_negative_until_monotonic_by_key)
        return 0.0, "local_fallback"
    expires_at_epoch = _parse_aawm_alias_routing_durable_expiry(durable_payload)
    if expires_at_epoch is None:
        async with _anthropic_auto_agent_lock:
            _anthropic_auto_agent_cooldown_negative_until_monotonic_by_key[cooldown_key] = (
                time.monotonic() + _AAWM_COOLDOWN_NEGATIVE_CACHE_TTL_SECONDS
            )
            _bound_aawm_alias_routing_memory_map(_anthropic_auto_agent_cooldown_negative_until_monotonic_by_key)
        return 0.0, "local_fallback"
    async with _anthropic_auto_agent_lock:
        _anthropic_auto_agent_cooldown_negative_until_monotonic_by_key.pop(cooldown_key, None)
        _hydrate_aawm_alias_routing_cooldown_memory(
            memory_map=_anthropic_auto_agent_cooldown_until_monotonic_by_key,
            cooldown_key=cooldown_key,
            expires_at_epoch=expires_at_epoch,
        )
        until = _anthropic_auto_agent_cooldown_until_monotonic_by_key.get(cooldown_key, 0.0)
        return max(0.0, until - time.monotonic()), "durable_cache"


async def _get_anthropic_auto_agent_active_cooldown_seconds(
    cooldown_key: str,
) -> float:
    seconds, _ = await _get_anthropic_auto_agent_active_cooldown_state(cooldown_key)
    return seconds


async def _set_anthropic_auto_agent_cooldown(
    cooldown_key: str,
    cooldown_seconds: float,
) -> None:
    ttl_seconds = max(0.0, float(cooldown_seconds))
    async with _anthropic_auto_agent_lock:
        until = time.monotonic() + ttl_seconds
        current_until = _anthropic_auto_agent_cooldown_until_monotonic_by_key.get(cooldown_key, 0.0)
        if until > current_until:
            _anthropic_auto_agent_cooldown_until_monotonic_by_key[cooldown_key] = until
            _anthropic_auto_agent_cooldown_negative_until_monotonic_by_key.pop(cooldown_key, None)
            _bound_aawm_alias_routing_memory_map(_anthropic_auto_agent_cooldown_until_monotonic_by_key)
    if ttl_seconds <= 0:
        return
    await _write_aawm_alias_routing_durable_payload(
        alias_family="anthropic",
        state_kind="cooldown",
        state_key=cooldown_key,
        payload={"cooldown_key": cooldown_key},
        ttl_seconds=ttl_seconds,
    )


async def _get_anthropic_auto_agent_session_affinity(
    session_key: Optional[str],
) -> Optional[dict[str, Any]]:
    if session_key is None:
        return None
    async with _anthropic_auto_agent_lock:
        affinity = _anthropic_auto_agent_session_affinity_by_key.get(session_key)
        if isinstance(affinity, dict):
            expires_at = affinity.get("expires_at_monotonic", 0.0)
            if isinstance(expires_at, (int, float)) and expires_at > time.monotonic():
                hydrated = dict(affinity)
                hydrated["affinity_state_source"] = affinity.get("affinity_state_source", "memory")
                return hydrated
            _anthropic_auto_agent_session_affinity_by_key.pop(session_key, None)
    dual_cache = _get_aawm_alias_routing_dual_cache()
    if dual_cache is None:
        return None
    durable_payload = await _read_aawm_alias_routing_durable_payload(
        alias_family="anthropic",
        state_kind="affinity",
        state_key=session_key,
    )
    if durable_payload is None:
        return None
    expires_at_epoch = _parse_aawm_alias_routing_durable_expiry(durable_payload)
    if expires_at_epoch is None:
        return None
    async with _anthropic_auto_agent_lock:
        affinity = _hydrate_aawm_alias_routing_affinity_memory(
            memory_map=_anthropic_auto_agent_session_affinity_by_key,
            session_key=session_key,
            payload=durable_payload,
            expires_at_epoch=expires_at_epoch,
        )
        if not affinity:
            return None
        affinity["affinity_state_source"] = "durable_cache"
        return dict(affinity)


async def _set_anthropic_auto_agent_session_affinity(
    session_key: Optional[str],
    candidate: dict[str, Any],
) -> None:
    if session_key is None:
        return
    async with _anthropic_auto_agent_lock:
        _anthropic_auto_agent_session_affinity_by_key[session_key] = {
            "provider": candidate["provider"],
            "model": candidate["model"],
            "route_family": candidate["route_family"],
            "last_resort": bool(candidate.get("last_resort")),
            "expires_at_monotonic": (time.monotonic() + _CODEX_AUTO_AGENT_SESSION_AFFINITY_TTL_SECONDS),
            "affinity_state_source": "memory",
        }
        _bound_aawm_alias_routing_memory_map(_anthropic_auto_agent_session_affinity_by_key)
    await _write_aawm_alias_routing_durable_payload(
        alias_family="anthropic",
        state_kind="affinity",
        state_key=session_key,
        payload={
            "provider": candidate["provider"],
            "model": candidate["model"],
            "route_family": candidate["route_family"],
            "last_resort": bool(candidate.get("last_resort")),
        },
        ttl_seconds=_CODEX_AUTO_AGENT_SESSION_AFFINITY_TTL_SECONDS,
    )


def _find_anthropic_auto_agent_candidate(
    provider: Any,
    model: Any,
    *,
    alias_model: str = _ANTHROPIC_AUTO_AGENT_MODEL_ALIAS,
) -> Optional[dict[str, Any]]:
    for candidate in _get_anthropic_auto_agent_candidates_for_alias(alias_model):
        if candidate["provider"] == provider and candidate["model"] == model:
            return dict(candidate)
    return None


async def _build_anthropic_auto_agent_candidate_states(
    request: Request,
    *,
    alias_model: str = _ANTHROPIC_AUTO_AGENT_MODEL_ALIAS,
) -> list[dict[str, Any]]:
    openai_lane_key = _resolve_codex_auto_agent_openai_cooldown_lane_key(request)
    anthropic_lane_key = _resolve_anthropic_auto_agent_native_cooldown_lane_key(request)
    google_lane_key: Optional[str] = None
    antigravity_lane_state: Optional[dict[str, Any]] = None
    states: list[dict[str, Any]] = []
    for candidate_template in _get_anthropic_auto_agent_candidates_for_alias(alias_model):
        if candidate_template["provider"] == _CODEX_AUTO_AGENT_GOOGLE_PROVIDER and google_lane_key is None:
            google_lane_key = await _resolve_codex_auto_agent_google_lane_key()
        if candidate_template["provider"] == _CODEX_AUTO_AGENT_ANTIGRAVITY_PROVIDER and antigravity_lane_state is None:
            antigravity_lane_state = await _resolve_codex_auto_agent_antigravity_lane_state()
        states.append(
            await _build_anthropic_auto_agent_candidate_state(
                request,
                candidate_template=candidate_template,
                alias_model=alias_model,
                openai_lane_key=openai_lane_key,
                anthropic_lane_key=anthropic_lane_key,
                google_lane_key=google_lane_key,
                antigravity_lane_state=antigravity_lane_state,
            )
        )
    return states


def _raise_anthropic_auto_agent_in_flight_cooldown(
    *,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    cooldown_seconds: float,
) -> None:
    shaped_candidate = _codex_auto_agent_candidate_public_shape(
        candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        reason="in_flight_session_affinity_cooldown",
    )
    raise HTTPException(
        status_code=429,
        detail={
            "error": {
                "message": (
                    "Anthropic auto-agent alias target is cooling down for an "
                    "in-flight session; provider switching is disabled for "
                    "stateful Claude continuations. Redispatch a fresh agent "
                    "attempt to re-run the auto selector."
                ),
                "type": "rate_limit_error",
                "code": "aawm_anthropic_auto_agent_in_flight_provider_cooling_down",
            },
            "candidate": shaped_candidate,
        },
        headers={"Retry-After": str(int(max(1.0, cooldown_seconds)))},
    )


def _raise_anthropic_auto_agent_redispatch_required(
    *,
    candidate: dict[str, Any],
    lane_key: Optional[str],
    cooldown_seconds: float,
    error_tokens: set[str],
    alias_model: str = _ANTHROPIC_AUTO_AGENT_MODEL_ALIAS,
    error_class: Optional[str] = None,
    cooldown_scope: Optional[str] = None,
    error_status_code: Optional[Any] = None,
    error_type: Optional[str] = None,
    error_code: Optional[Any] = None,
    retry_after_seconds: Optional[Any] = None,
    failure_phase: Optional[str] = None,
    attempted_provider_call: Optional[bool] = None,
    audit_events: Optional[list[dict[str, Any]]] = None,
    attempts: Optional[list[dict[str, Any]]] = None,
    skipped_candidates: Optional[list[dict[str, Any]]] = None,
) -> None:
    detail = _build_auto_agent_redispatch_http_exception_detail(
        alias_family="anthropic_auto_agent",
        alias_model=alias_model,
        candidate=candidate,
        lane_key=lane_key,
        cooldown_seconds=cooldown_seconds,
        error_tokens=error_tokens,
        error_class=error_class,
        cooldown_scope=cooldown_scope,
        error_status_code=error_status_code,
        error_type=error_type,
        error_code=error_code,
        retry_after_seconds=retry_after_seconds,
        failure_phase=failure_phase,
        attempted_provider_call=attempted_provider_call,
        audit_events=audit_events,
        attempts=attempts,
        skipped_candidates=skipped_candidates,
        code="aawm_anthropic_auto_agent_redispatch_required",
        message=(
            "Anthropic auto-agent alias target hit retryable provider "
            "exhaustion for an in-flight session. Do not continue this "
            f"child agent. Redispatch a fresh subagent using model {alias_model} "
            "so the auto selector can choose the next available candidate."
        ),
    )
    raise HTTPException(
        status_code=429,
        detail=detail,
        headers={"Retry-After": str(detail["retry_after_seconds"])},
    )


async def _select_anthropic_auto_agent_candidate(
    *,
    request: Request,
    request_body: dict[str, Any],
) -> dict[str, Any]:
    alias_model = (
        _normalize_anthropic_auto_agent_alias_model(request_body.get("model")) or _ANTHROPIC_AUTO_AGENT_MODEL_ALIAS
    )
    session_key = _resolve_anthropic_auto_agent_session_key(
        request,
        request_body,
        alias_model=alias_model,
    )
    has_continuation_state = _codex_auto_agent_request_has_continuation_state(request_body)

    affinity = await _get_anthropic_auto_agent_session_affinity(session_key)
    if affinity is not None and not has_continuation_state:
        affinity = None
    if affinity is not None and has_continuation_state:
        affinity_candidate = _find_anthropic_auto_agent_candidate(
            affinity.get("provider"),
            affinity.get("model"),
            alias_model=alias_model,
        )
        if affinity_candidate is not None:
            affinity_state = await _build_anthropic_auto_agent_candidate_state(
                request,
                candidate_template=affinity_candidate,
                alias_model=alias_model,
            )
            if _is_auto_agent_candidate_state_available(affinity_state):
                return _attach_aawm_alias_routing_state_sources(
                    {
                        **affinity_state,
                        "alias_model": alias_model,
                        "session_key": session_key,
                        "selection_reason": "session_affinity",
                        "skipped": [],
                        "in_flight_session": has_continuation_state,
                    },
                    affinity=affinity,
                    selected_state=affinity_state,
                )
            if affinity_state["cooldown_seconds"] > 0:
                _raise_anthropic_auto_agent_in_flight_cooldown(
                    candidate=affinity_candidate,
                    lane_key=affinity_state.get("lane_key"),
                    cooldown_seconds=affinity_state["cooldown_seconds"],
                )

    states = await _build_anthropic_auto_agent_candidate_states(
        request,
        alias_model=alias_model,
    )
    skipped = _build_auto_agent_skipped_candidates_from_states(states)

    if affinity is not None:
        affinity_candidate = _find_anthropic_auto_agent_candidate(
            affinity.get("provider"),
            affinity.get("model"),
            alias_model=alias_model,
        )
        if affinity_candidate is not None:
            matched_affinity_state: Optional[dict[str, Any]] = None
            for state in states:
                if (
                    state["candidate"]["provider"] == affinity_candidate["provider"]
                    and state["candidate"]["model"] == affinity_candidate["model"]
                ):
                    matched_affinity_state = state
                    break
            if matched_affinity_state is not None:
                if not _is_auto_agent_candidate_state_available(matched_affinity_state):
                    if has_continuation_state:
                        if matched_affinity_state["cooldown_seconds"] > 0:
                            _raise_anthropic_auto_agent_in_flight_cooldown(
                                candidate=affinity_candidate,
                                lane_key=matched_affinity_state.get("lane_key"),
                                cooldown_seconds=matched_affinity_state["cooldown_seconds"],
                            )
                    skipped.append(
                        _codex_auto_agent_candidate_public_shape(
                            affinity_candidate,
                            lane_key=matched_affinity_state.get("lane_key"),
                            cooldown_seconds=(
                                matched_affinity_state["cooldown_seconds"]
                                if matched_affinity_state["cooldown_seconds"] > 0
                                else None
                            ),
                            reason=matched_affinity_state.get("skip_reason") or "session_affinity_cooldown",
                        )
                    )
                else:
                    return _attach_aawm_alias_routing_state_sources(
                        {
                            **matched_affinity_state,
                            "alias_model": alias_model,
                            "session_key": session_key,
                            "selection_reason": "session_affinity",
                            "skipped": skipped,
                            "in_flight_session": has_continuation_state,
                        },
                        affinity=affinity,
                        selected_state=matched_affinity_state,
                    )

    for state in states:
        if state["candidate"].get("last_resort") or not _is_auto_agent_candidate_state_available(state):
            continue
        return _attach_aawm_alias_routing_state_sources(
            {
                **state,
                "alias_model": alias_model,
                "session_key": session_key,
                "selection_reason": "first_available",
                "skipped": skipped,
                "in_flight_session": has_continuation_state,
            },
            selected_state=state,
        )

    for state in states:
        if not state["candidate"].get("last_resort") or not _is_auto_agent_candidate_state_available(state):
            continue
        return _attach_aawm_alias_routing_state_sources(
            {
                **state,
                "alias_model": alias_model,
                "session_key": session_key,
                "selection_reason": "last_resort",
                "skipped": skipped,
                "in_flight_session": has_continuation_state,
            },
            selected_state=state,
        )

    raise HTTPException(
        status_code=429,
        detail={
            "error": {
                "message": ("All Anthropic auto-agent alias candidates are currently cooled down."),
                "type": "rate_limit_error",
                "code": "aawm_anthropic_auto_agent_all_candidates_cooling_down",
            },
            "candidates": skipped,
        },
    )


def _add_anthropic_auto_agent_alias_metadata(
    request_body: dict[str, Any],
    *,
    request: Request,
    selection: dict[str, Any],
    attempts: list[dict[str, Any]],
) -> dict[str, Any]:
    candidate = selection["candidate"]
    alias_model = (
        selection.get("alias_model")
        or _normalize_anthropic_auto_agent_alias_model(request_body.get("model"))
        or _ANTHROPIC_AUTO_AGENT_MODEL_ALIAS
    )
    target_model = candidate["model"]
    updated_body = copy.deepcopy(request_body)
    updated_body["model"] = target_model
    skipped = selection.get("skipped") or []
    audit_events = _build_auto_agent_alias_audit_events(
        alias_family="anthropic_auto_agent",
        alias_model=alias_model,
        request=request,
        request_body=request_body,
        selection=selection,
        attempts=attempts,
    )
    return _merge_litellm_metadata(
        updated_body,
        tags_to_add=[
            "anthropic-auto-agent-alias",
            f"anthropic-auto-agent-selected:{target_model}",
            f"anthropic-auto-agent-route:{candidate['route_family']}",
            f"model-alias:{alias_model}",
            *(["anthropic-auto-agent-last-resort"] if candidate.get("last_resort") else []),
            f"anthropic-auto-agent-alias:{alias_model}",
        ],
        extra_fields={
            "model_alias_label": alias_model,
            "requested_model_alias": alias_model,
            "anthropic_auto_agent_alias": alias_model,
            "anthropic_auto_agent_selected_provider": candidate["provider"],
            "anthropic_auto_agent_selected_model": target_model,
            "anthropic_auto_agent_selected_route_family": candidate["route_family"],
            "anthropic_auto_agent_selected_last_resort": bool(candidate.get("last_resort")),
            "anthropic_auto_agent_selection_reason": selection.get("selection_reason"),
            "anthropic_auto_agent_affinity_state_source": selection.get("affinity_state_source"),
            "anthropic_auto_agent_cooldown_state_source": selection.get("cooldown_state_source"),
            "anthropic_auto_agent_lane_key": selection.get("lane_key"),
            "anthropic_auto_agent_attempts": attempts,
            "anthropic_auto_agent_skipped_candidates": skipped,
            "anthropic_auto_agent_audit_events": audit_events,
            "aawm_alias_routing_audit_events": audit_events,
        },
    )


