def _codex_google_code_assist_tool_result_content_to_openai_content(
    content: Any,
) -> Any:
    if content is None:
        return ""
    if isinstance(content, str):
        return content
    if isinstance(content, list):
        text_parts: list[str] = []
        for item in content:
            if isinstance(item, str):
                text_parts.append(item)
                continue
            if isinstance(item, dict) and item.get("type") == "text":
                text = item.get("text")
                if isinstance(text, str):
                    text_parts.append(text)
        if text_parts:
            return "".join(text_parts)
    try:
        return json.dumps(content, ensure_ascii=False, default=str)
    except Exception:
        return str(content)


def _codex_google_code_assist_anthropic_tool_use_to_openai_tool_call(
    *,
    block: dict[str, Any],
    message_index: int,
    content_index: int,
) -> dict[str, Any]:
    tool_use_id = block.get("id")
    if not isinstance(tool_use_id, str) or not tool_use_id.strip():
        raise HTTPException(
            status_code=400,
            detail=(
                "Invalid Anthropic tool_use block at "
                f"messages.{message_index}.content.{content_index}: "
                "missing required non-empty string tool_use.id"
            ),
        )
    tool_input = block.get("input")
    if not isinstance(tool_input, dict):
        tool_input = {}
    return {
        "id": tool_use_id.strip(),
        "type": "function",
        "function": {
            "name": str(block.get("name") or ""),
            "arguments": json.dumps(tool_input, ensure_ascii=False),
        },
    }


